DROP TABLE IF EXISTS `lkt_activity`;
CREATE TABLE `lkt_activity` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `activity_type` tinyint NOT NULL DEFAULT '1' COMMENT '类型 0.活动专题 1.营销插件',
  `plug_type` tinyint NOT NULL DEFAULT '1' COMMENT '插件类型 ',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '标题',
  `subtitle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '副标题',
  `is_image` tinyint NOT NULL DEFAULT '0' COMMENT '是否有宣传图 0.没有宣传图 1.有宣传图',
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '宣传图',
  `url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '跳转路径',
  `p_id` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '商品ID',
  `is_display` tinyint NOT NULL DEFAULT '0' COMMENT '是否显示 0.不显示 1.显示',
  `sort` int DEFAULT '100' COMMENT '排序',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `subtraction_id` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '满减ID',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='活动表';

