-- ----------------------------
-- Table structure for lkt_admin
-- ----------------------------
DROP TABLE IF EXISTS `lkt_admin`;
CREATE TABLE `lkt_admin` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `sid` int NOT NULL DEFAULT '0' COMMENT '上级id',
  `name` varchar(30) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '账号（为了区分大小写,请设置字段为utf8-utf8_bin）',
  `password` char(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '密码',
  `admin_type` int DEFAULT '1' COMMENT '管理类型 0=平台管理员',
  `permission` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '许可',
  `role` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '角色 ',
  `type` int DEFAULT '0' COMMENT '类型 0:系统管理员 1：客户 2:商城管理员 3:店主',
  `store_id` int DEFAULT '0' COMMENT '商城id',
  `shop_id` int NOT NULL DEFAULT '0' COMMENT '店铺ID',
  `status` int NOT NULL DEFAULT '2' COMMENT '状态 1:禁用 2：启用',
  `portrait` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '管理员头像',
  `nickname` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '昵称',
  `birthday` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '生日',
  `sex` int DEFAULT '1' COMMENT '性别（1 男  2 女）',
  `tel` varchar(22) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '手机号码',
  `token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '令牌',
  `ip` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '登入ip地址',
  `recycle` tinyint DEFAULT NULL COMMENT '回收站 0:不回收 1:回收 ',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `login_num` int NOT NULL DEFAULT '0' COMMENT '登录次数',
  `lang` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'zh-cn' COMMENT '语言',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=772 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='管理员表';

