-- ----------------------------
-- Table structure for lkt_auction_product
-- ----------------------------
DROP TABLE IF EXISTS `lkt_auction_product`;
CREATE TABLE `lkt_auction_product` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id',
  `session_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '场次id',
  `goods_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '商品id',
  `attr_id` int DEFAULT '0' COMMENT '商品规格id',
  `starting_amt` decimal(12,2) DEFAULT NULL COMMENT '起拍价',
  `mark_up_amt` decimal(12,2) DEFAULT NULL COMMENT '加价幅度',
  `goods_price` decimal(12,2) DEFAULT NULL COMMENT '商品价格',
  `price` decimal(12,2) DEFAULT NULL COMMENT '当前出价',
  `user_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '最终得主',
  `status` int DEFAULT '0' COMMENT '0=待拍卖 1=拍卖中 2=已拍卖 3=已流拍',
  `sNo` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '关联订单号',
  `is_show` int DEFAULT '0' COMMENT '是否显示',
  `recovery` int DEFAULT '0' COMMENT '回收标识',
  `add_date` datetime DEFAULT NULL COMMENT '添加时间',
  `update_date` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `passed_status` int DEFAULT '1' COMMENT '流拍类型  1未付款流拍  2未达到人数流拍  ',
  PRIMARY KEY (`id`) USING BTREE
