  `is_pay` int DEFAULT NULL COMMENT '是否成功支付 0失败,1成功',
  `is_back` int DEFAULT NULL COMMENT '是否退款成功  0-成功 1-失败',
  `is_deduction` int DEFAULT '0' COMMENT '是否扣除 0=未扣除,1=已扣除',
  `allow_back` tinyint DEFAULT '1' COMMENT '是否符合退款标准  0：不符合 1：符合',
