  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '文件名称',
  `file_size` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '文件大小',
  `file_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '文件类型',
  `file_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '文件路径',
  `status` int DEFAULT NULL COMMENT '状态',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `recycle` int NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.系统回收 2用户回收 3店铺回收',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='数据备份记录表';

-- ----------------------------
-- Records of lkt_backup_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_bank_card
-- ----------------------------
DROP TABLE IF EXISTS `lkt_bank_card`;
CREATE TABLE `lkt_bank_card` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `store_id` int NOT NULL COMMENT '商城ID',
  `user_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户ID',
  `mch_id` int DEFAULT NULL COMMENT '店铺id',
  `Cardholder` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '开户人',
  `Bank_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '银行名称',
  `branch` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '支行名称',
  `Bank_card_number` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '银行卡号',
  `add_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认 1默认',
  `recycle` tinyint(1) NOT NULL DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  PRIMARY KEY (`id`) USING BTREE
