-- ----------------------------
-- Table structure for lkt_banner
-- ----------------------------
DROP TABLE IF EXISTS `lkt_banner`;
CREATE TABLE `lkt_banner` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `image` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '图片',
  `open_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '跳转方式',
  `url` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '链接',
  `sort` int DEFAULT NULL COMMENT '排序',
  `type` tinyint DEFAULT '1' COMMENT '类型 1.分类 2.商品 3.店铺 4.pc店铺 0=自定义',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `mch_id` int DEFAULT '0' COMMENT '店铺ID',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='轮播图表';

