COMMIT;

-- ----------------------------
-- Table structure for lkt_bargain_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_bargain_config`;
CREATE TABLE `lkt_bargain_config` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int NOT NULL DEFAULT '1' COMMENT '商城id',
  `buy_time` int NOT NULL DEFAULT '10' COMMENT '购买时间',
  `show_time` int NOT NULL DEFAULT '3' COMMENT '商品结束后还显示的时间',
  `only_times` int NOT NULL DEFAULT '2' COMMENT '一个人可对一个商品参加的砍价次数',
  `rule` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '砍价规则',
  `imgurl` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '砍价顶部图片',
  `addtime` int NOT NULL DEFAULT '0' COMMENT '添加时间',
  `updatetime` int NOT NULL DEFAULT '0' COMMENT '修改时间',
  `status` int NOT NULL DEFAULT '0' COMMENT '插件状态 0关闭 1开启',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='砍价配置表';

-- ----------------------------
-- Records of lkt_bargain_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_bargain_goods
-- ----------------------------
DROP TABLE IF EXISTS `lkt_bargain_goods`;
CREATE TABLE `lkt_bargain_goods` (
  `id` int NOT NULL AUTO_INCREMENT,
  `store_id` int NOT NULL DEFAULT '0',
  `goods_id` int NOT NULL DEFAULT '0',
  `attr_id` int NOT NULL COMMENT '产品属性id',
  `is_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '产品属性值1.猜你喜欢，2.热销，3.新品',
  `min_price` decimal(11,2) NOT NULL COMMENT '最低价',
  `begin_time` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '活动开始时间',
  `end_time` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '活动结束时间',
  `buytime` int NOT NULL DEFAULT '0' COMMENT '购买时间',
  `man_num` smallint NOT NULL DEFAULT '0' COMMENT '砍价人数 0为不限制',
  `status_data` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '砍价方式数据',
  `status` smallint NOT NULL DEFAULT '0' COMMENT '状态0.未开始1.进行中2.已结束',
  `is_show` smallint NOT NULL DEFAULT '1' COMMENT '是否显示:0,不显示   1,显示',
  `addtime` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0',
  `sort` int NOT NULL DEFAULT '1' COMMENT '权重值，越大排序越靠前',
  `is_delete` smallint NOT NULL DEFAULT '0' COMMENT '是否删除:0否   1是',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `goods_id` (`goods_id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='砍价商品表';

-- ----------------------------
-- Records of lkt_bargain_goods
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_bargain_order
-- ----------------------------
DROP TABLE IF EXISTS `lkt_bargain_order`;
CREATE TABLE `lkt_bargain_order` (
  `id` int NOT NULL AUTO_INCREMENT,
  `store_id` int NOT NULL DEFAULT '0',
  `user_id` char(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0',
  `order_no` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0',
  `attr_id` int NOT NULL DEFAULT '0',
  `original_price` decimal(10,2) NOT NULL COMMENT '剩余价格',
  `min_price` decimal(10,2) NOT NULL COMMENT '商品最低价',
  `goods_id` int NOT NULL,
  `status` int NOT NULL DEFAULT '0' COMMENT '状态 -1--失败 0--进行中 1--成功 2--付款',
  `is_delete` int NOT NULL DEFAULT '0',
  `addtime` int NOT NULL DEFAULT '0',
  `status_data` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '砍价方式数据',
  `bargain_id` int NOT NULL COMMENT '砍价活动id',
  `achievetime` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `user_id` (`user_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='发起砍价订单表';

-- ----------------------------
-- Records of lkt_bargain_order
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_bargain_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_bargain_record`;
CREATE TABLE `lkt_bargain_record` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int DEFAULT NULL,
  `order_no` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '砍价订单',
  `user_id` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `money` decimal(12,2) NOT NULL COMMENT '金额',
  `add_time` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '添加时间',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 0:砍价中 1:砍价成功 2:逾期失效 3:生成订单',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `id` (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='砍价免单记录表';

-- ----------------------------
-- Records of lkt_bargain_record
-- ----------------------------
BEGIN;
COMMIT;

