-- Table structure for lkt_block_home
-- ----------------------------
DROP TABLE IF EXISTS `lkt_block_home`;
CREATE TABLE `lkt_block_home` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `block_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '楼层名称',
