  `recycle` int DEFAULT NULL COMMENT '回收标志',
  `store_id` int DEFAULT NULL COMMENT '商城id',
  `enable_or_not` int DEFAULT '1' COMMENT '楼层是否开启显示 1显示  2不显示',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='楼层管理';

