-- ----------------------------
-- Table structure for lkt_bond
-- ----------------------------
DROP TABLE IF EXISTS `lkt_bond`;
CREATE TABLE `lkt_bond` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int NOT NULL COMMENT '商城id',
  `money` decimal(12,2) NOT NULL COMMENT '保证金金额',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户userid',
  `trade_no` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单编号',
  `type` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '支付方式',
  `is_pay` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否支付（1是 0否）',
  `is_back` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否退款（1是 0否）',
  `add_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='提现保证金记录表';

