COMMIT;

-- ----------------------------
-- Table structure for lkt_brand_class
-- ----------------------------
DROP TABLE IF EXISTS `lkt_brand_class`;
CREATE TABLE `lkt_brand_class` (
  `brand_id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '品牌id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `brand_pic` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '品牌logo',
  `brand_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '广告图',
  `brand_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '品牌名称',
  `brand_y_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '英文名',
  `producer` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '产地',
  `remarks` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '说明',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 0:启用 1:禁用',
  `brand_time` timestamp NULL DEFAULT NULL COMMENT '时间',
  `sort` int DEFAULT '100',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  `categories` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '所属分类',
  `is_default` int DEFAULT '0' COMMENT '是否默认分类',
  `examine` int DEFAULT NULL COMMENT '审核状态 0.待审核 1.审核通过 2.不通过',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '审核备注',
  `mch_id` int DEFAULT NULL COMMENT '店铺id',
  `supplier_id` int DEFAULT NULL COMMENT '供应商id',
  PRIMARY KEY (`brand_id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `recycle` (`recycle`) USING BTREE,
  KEY `recycle_2` (`recycle`) USING BTREE,
  KEY `status` (`status`) USING BTREE,
  KEY `brand_name` (`brand_name`(191)) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商品品牌表';

-- ----------------------------
-- Records of lkt_brand_class
-- ----------------------------
BEGIN;
COMMIT;

