  `transaction_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '微信支付订单号',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 1.成功 2.失败',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '二维码生成时间',
  `success_time` timestamp NULL DEFAULT NULL COMMENT '支付完成时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='收银台记录表';

