-- ----------------------------
-- Table structure for lkt_comments
-- ----------------------------
DROP TABLE IF EXISTS `lkt_comments`;
CREATE TABLE `lkt_comments` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `oid` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `uid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户id',
  `pid` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '商品id',
  `attribute_id` int DEFAULT NULL COMMENT '属性id',
  `size` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '默认' COMMENT '商品规格',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '评价内容',
  `CommentType` char(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '评价类型',
  `anonymous` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '匿名 ',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `review` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '追评',
  `review_time` timestamp NULL DEFAULT NULL COMMENT '追评时间',
  `type` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '评价类型-KJ 砍价评论-PT 拼团评论',
  `order_detail_id` int NOT NULL DEFAULT '0' COMMENT '订单详情id',
  `is_look` int NOT NULL DEFAULT '0' COMMENT '商家是否以查看评论 0未查看 1已查看',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `attribute_id` (`attribute_id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `oid` (`oid`) USING BTREE,
  KEY `uid` (`uid`) USING BTREE,
  KEY `pid` (`pid`) USING BTREE,
  KEY `attribute_id_2` (`attribute_id`) USING BTREE,
  KEY `order_detail_id` (`order_detail_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='评论表';

-- ----------------------------
-- Records of lkt_comments
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_comments_img
-- ----------------------------
DROP TABLE IF EXISTS `lkt_comments_img`;
CREATE TABLE `lkt_comments_img` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '图片id',
  `comments_url` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '评论图片',
  `comments_id` int DEFAULT NULL COMMENT '评论id',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `type` tinyint DEFAULT '0' COMMENT '类型 0:评论  1:追评',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='评论图片表';

-- ----------------------------
-- Records of lkt_comments_img
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_config`;
CREATE TABLE `lkt_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `is_register` tinyint NOT NULL DEFAULT '0' COMMENT '是否需要注册 1.注册 2.免注册',
  `logo` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '公司logo',
  `logo1` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '首页logo',
  `company` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '公司名称',
  `appid` char(18) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '小程序id',
  `appsecret` char(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '小程序密钥',
  `domain` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '商城根目录域名',
  `app_domain_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'APP域名',
  `H5_domain` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'H5地址',
  `mch_id` int DEFAULT NULL COMMENT '商户id',
  `ip` varchar(25) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'ip地址',
  `uploadImg_domain` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '图片上传域名',
  `upserver` tinyint NOT NULL DEFAULT '2' COMMENT '上传服务器:1,本地　2,阿里云 3,腾讯云 4,七牛云 5,minio',
  `uploadImg` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '图片上传位置',
  `upload_file` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '文件上传位置',
  `modify_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `mch_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '微信支付key',
  `mch_cert` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '支付证书文件地址',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '用户ID默认前缀',
  `wx_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '默认微信名称',
  `wx_headimgurl` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '默认微信头像',
  `customer_service` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '客服',
  `agreement` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '用户协议',
  `aboutus` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '关于我们',
  `message_day` int NOT NULL DEFAULT '0' COMMENT '消息保留天数',
  `tencent_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '腾讯位置服务开发密钥',
  `after_sales_issues` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '售后问题',
  `payment_issues` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '支付问题',
  `shopping_process` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '购物流程',
  `payment_method` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '付款方式',
  `return_policy` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '退货政策',
  `cancellation_order` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '取消订单',
  `refund_process` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '退款流程',
  `refund_instructions` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '退款说明',
  `exp_time` int DEFAULT '2' COMMENT '移动端登录有效期',
  `is_push` tinyint DEFAULT '1' COMMENT '是否推送 0.不推送 1.推送',
  `push_Appkey` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '推送Appkey',
  `push_Appid` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '推送Appid',
  `push_MasterECRET` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '推送秘钥',
  `is_express` tinyint DEFAULT '1' COMMENT '是否开启快递100  0.不开启 1.开\r\n\r\n启',
  `express_address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '查询接口地址',
  `express_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户编号',
  `express_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '接口调用key',
  `express_secret` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT 'secret在企业管理后台获取',
  `express_temp_id` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '主单模板',
  `is_Kicking` tinyint DEFAULT '0' COMMENT '是否登录踢人  0.不开启 1.开启',
  `Hide_your_wallet` tinyint DEFAULT '0' COMMENT '是否隐藏钱包 0.不隐藏 1.隐藏',
  `watermark_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '水印名称',
  `watermark_url` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '水印网址',
  `pc_mch_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'PC店铺地址',
  `app_title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '小程序首页标题',
  `app_logo` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '小程序授权登录logo',
  `is_accounts` int DEFAULT NULL COMMENT '是否分账',
  `accounts_set` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '分账账号',
  `logon_logo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '登录logo',
  `copyright_information` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '版权信息',
  `record_information` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备案信息',
  `link_to_landing_page` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '登录页友情链接',
  `admin_default_portrait` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '默认头像设置',
  `android_download_link` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '安卓下载地址',
  `ios_download_link` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'IOS下载地址',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='系统配置表';

-- ----------------------------
-- Records of lkt_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_configure
-- ----------------------------
DROP TABLE IF EXISTS `lkt_configure`;
CREATE TABLE `lkt_configure` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '配置id',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '配置名称',
  `color` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '颜色',
  `size` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '尺码',
  `costprice` decimal(12,2) NOT NULL COMMENT '成本价',
  `price` decimal(12,2) NOT NULL COMMENT '出售价格',
  `yprice` decimal(12,2) NOT NULL COMMENT '原价格',
  `msrp` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '建议零售价',
  `img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '图片',
  `pid` int NOT NULL COMMENT '商品id',
  `total_num` int NOT NULL DEFAULT '0' COMMENT '总库存',
  `num` int unsigned NOT NULL DEFAULT '0' COMMENT '剩余库存',
  `unit` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '单位',
  `bar_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '条形码',
  `bargain_price` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '砍价开始价格',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 0:未开启砍价 1:开启砍价 2 上架 3 缺货 4下架',
  `attribute` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '属性',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  `min_inventory` int NOT NULL DEFAULT '10' COMMENT '产品预警值',
  `ctime` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  `attribute_str` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '属性ID字符串',
  `supplier_superior` int DEFAULT NULL COMMENT '供应商商品规格上级id',
  `write_off_num` int DEFAULT '0' COMMENT '虚拟商品可核销次数(暂时未使用，使用的总库存)',
  `commission` varchar(25) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '分佣比例',
  `update_time` timestamp NULL DEFAULT NULL COMMENT '修改佣金比例的时间',
  `live_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '直播价格',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `id` (`id`) USING BTREE,
  KEY `pid` (`pid`) USING BTREE,
  KEY `recycle` (`recycle`) USING BTREE,
  KEY `name` (`name`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商品规格配置表';

-- ----------------------------
-- Records of lkt_configure
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_core_menu
-- ----------------------------
DROP TABLE IF EXISTS `lkt_core_menu`;
CREATE TABLE `lkt_core_menu` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `s_id` int DEFAULT NULL COMMENT '上级id',
  `title` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '菜单名称',
  `name` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '菜单标识',
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '图标',
  `image1` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '点击后图标',
  `module` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '菜单模块标识',
  `action` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '菜单文件标识',
  `url` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '路径',
  `sort` int DEFAULT '0' COMMENT '菜单排序',
  `level` int DEFAULT NULL COMMENT '第几级',
  `is_core` tinyint DEFAULT '0' COMMENT '是否是核心',
  `is_plug_in` tinyint DEFAULT '0' COMMENT '是否是插件',
  `type` tinyint DEFAULT '0' COMMENT '类型 0=控制台 1=商城',
  `add_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '添加时间',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  `is_display` tinyint DEFAULT '0' COMMENT '是否显示 0.不显示 1.显示',
  `briefintroduction` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '简介',
  `guide_sort` int DEFAULT '0' COMMENT '导览排序',
  `guide_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '导览名称',
  `is_button` int DEFAULT '0' COMMENT '是否为按钮',
  `is_tab` int DEFAULT '0' COMMENT '是否为tab页面    0不是  1是',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `id` (`id`) USING BTREE,
  KEY `s_id` (`s_id`) USING BTREE,
  KEY `sort` (`sort`) USING BTREE,
  KEY `recycle` (`recycle`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1374 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='核心菜单';

