-- ----------------------------
-- Table structure for lkt_coupon
-- ----------------------------
DROP TABLE IF EXISTS `lkt_coupon`;
CREATE TABLE `lkt_coupon` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int DEFAULT '0' COMMENT '店铺ID',
  `user_id` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `money` int NOT NULL DEFAULT '0' COMMENT '优惠券金额',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '领取时间',
  `expiry_time` timestamp NULL DEFAULT NULL COMMENT '到期时间',
  `hid` int NOT NULL DEFAULT '0' COMMENT '活动id',
  `type` tinyint NOT NULL DEFAULT '0' COMMENT '类型 0:未使用 1:使用中 2:已使\r\n\r\n用 3:已过期',
  `status` tinyint DEFAULT '0' COMMENT '状态 0.开启 1.禁用',
  `free_or_not` tinyint DEFAULT '0' COMMENT '是否为赠送 0.不为赠送 1.赠送',
  `recycle` tinyint DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='优惠券表';

-- ----------------------------
-- Records of lkt_coupon
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_coupon_activity
-- ----------------------------
DROP TABLE IF EXISTS `lkt_coupon_activity`;
CREATE TABLE `lkt_coupon_activity` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int DEFAULT '0' COMMENT '店铺id',
  `name` varchar(25) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '优惠券名称',
  `activity_type` int DEFAULT '0' COMMENT '优惠券类型 1=免邮 2=满减 3=折扣 4=会员赠送',
  `grade_id` int DEFAULT NULL COMMENT '会员等级ID',
  `money` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '优惠券面值',
  `discount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '折扣值',
  `z_money` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '消费满多少',
  `shopping` int NOT NULL DEFAULT '0' COMMENT '满多少赠券',
  `free_mail_task` tinyint NOT NULL DEFAULT '0' COMMENT '免邮任务 0：完善资料 1：绑定手机',
  `circulation` int DEFAULT '0' COMMENT '发行数量',
  `num` int DEFAULT NULL COMMENT '剩余数量',
  `receive` int DEFAULT NULL COMMENT '领取限制',
  `use_num` int DEFAULT NULL COMMENT '使用限制',
  `start_time` timestamp NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` timestamp NULL DEFAULT NULL COMMENT '结束时间',
  `type` tinyint DEFAULT '1' COMMENT '优惠券使用范围 1：全部商品 2:指定商品 3：指定分类\r\n4：充值会员',
  `product_class_id` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '活动指定商品类型id',
  `product_id` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '活动指定商品id',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '备注',
  `skip_type` tinyint DEFAULT '1' COMMENT '跳转方式 1.首页 2.\r\n\r\n自定义',
  `url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '跳转路径',
  `status` tinyint DEFAULT '0' COMMENT '状态 0：未启用 1：启用 2:禁用 3：已结束',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `qualifications` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '资格',
  `recycle` tinyint DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  `day` int DEFAULT NULL COMMENT '有效时间',
  `Instructions` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '使用说明',
  `is_display` tinyint DEFAULT '1' COMMENT '是否显示 0.不显示 1.显示',
  `issue_unit` int DEFAULT '1' COMMENT '发行单位 0=商城 1=店铺',
  `receive_type` int DEFAULT '0' COMMENT '领取方式 0=手动领取 1=系统赠送',
  `is_auto_push` int DEFAULT '0' COMMENT '是否已自动发放',
  `cover_map` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '优惠券图片',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='优惠劵活动表';

-- ----------------------------
-- Records of lkt_coupon_activity
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_coupon_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_coupon_config`;
CREATE TABLE `lkt_coupon_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int DEFAULT '0' COMMENT '店铺id',
  `is_status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 0：未启用 1：启用',
  `coupon_del` tinyint DEFAULT NULL COMMENT '优惠券删除',
  `coupon_day` int DEFAULT NULL COMMENT '优惠券删除天数',
  `activity_del` tinyint DEFAULT NULL COMMENT '优惠券活动删除',
  `activity_day` int DEFAULT NULL COMMENT '优惠券活动删除天数',
  `payment_type` tinyint NOT NULL DEFAULT '0' COMMENT '支付设置 0：只使用优惠券 1：可与其他优惠一起使用',
  `limit_type` tinyint NOT NULL DEFAULT '0' COMMENT '限领设置 0：单张 1：多张',
  `coupon_type` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '优惠券类型',
  `modify_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `is_show` int NOT NULL DEFAULT '1' COMMENT '新增插件是否显示',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='优惠券设置表';

-- ----------------------------
-- Records of lkt_coupon_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_coupon_presentation_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_coupon_presentation_record`;
CREATE TABLE `lkt_coupon_presentation_record` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `coupon_activity_id` int NOT NULL DEFAULT '0' COMMENT '优惠券活动id',
  `coupon_id` int NOT NULL DEFAULT '0' COMMENT '优惠券id',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `mobile` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '手机号',
  `activity_type` int NOT NULL DEFAULT '0' COMMENT '优惠券类型',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='赠送优惠券记录表';

-- ----------------------------
-- Records of lkt_coupon_presentation_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_coupon_sno
-- ----------------------------
DROP TABLE IF EXISTS `lkt_coupon_sno`;
CREATE TABLE `lkt_coupon_sno` (
  `id` int NOT NULL AUTO_INCREMENT,
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `coupon_id` int NOT NULL DEFAULT '0' COMMENT '优惠券id',
  `sNo` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '订单号',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0:正常 1:回收',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='优惠券关联表';

-- ----------------------------
-- Records of lkt_coupon_sno
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_customer
-- ----------------------------
DROP TABLE IF EXISTS `lkt_customer`;
CREATE TABLE `lkt_customer` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `admin_id` int NOT NULL DEFAULT '0' COMMENT '管理员id',
  `customer_number` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '客户编号',
  `name` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '姓名',
  `mobile` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '手机',
  `price` decimal(12,2) NOT NULL COMMENT '价格',
  `company` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '公司名称',
  `function` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '功能',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '购买时间',
  `end_date` timestamp NULL DEFAULT NULL COMMENT '到期时间',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '类型 0:启用 1:到期 2:锁定',
  `email` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '邮箱',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0:不回收 1:回收 ',
  `is_default` tinyint DEFAULT '0' COMMENT '是否默认 0.不是默认 1.默认',
  `contact_address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '联系地址',
  `contact_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '联系电话',
  `copyright_information` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '版权信息',
  `record_information` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备案信息',
  `official_website` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '官方网址',
  `merchant_logo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '商户logo',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商城表';

-- ----------------------------
-- Records of lkt_customer
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_data_dictionary_list
-- ----------------------------
DROP TABLE IF EXISTS `lkt_data_dictionary_list`;
CREATE TABLE `lkt_data_dictionary_list` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '编码',
  `sid` int NOT NULL DEFAULT '0' COMMENT '数据字典名称ID',
  `s_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '上级名称',
  `value` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'value',
  `ctext` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '值',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '是否生效 0:不是 1:是',
  `admin_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '管理员名称',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0:正常 1:回收',
  `add_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=340 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='数据字典目录表';

