-- ----------------------------
-- Table structure for lkt_data_dictionary_name
-- ----------------------------
DROP TABLE IF EXISTS `lkt_data_dictionary_name`;
CREATE TABLE `lkt_data_dictionary_name` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '名称',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '是否生效 0:不是 1:是',
  `admin_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '管理员名称',
  `dic_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '字典代码',
  `is_core` int NOT NULL DEFAULT '0' COMMENT '是否是系统核心字典',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0:正常 1:回收',
  `add_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=149 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='数据字典名称表';

