-- ----------------------------
-- Table structure for lkt_distribution_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_distribution_config`;
CREATE TABLE `lkt_distribution_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `sets` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `status` int NOT NULL DEFAULT '0' COMMENT '插件状态 0关闭 1开启',
  `advertising` tinyint(1) NOT NULL DEFAULT '0' COMMENT '加盟广告（0不开启1开启）',
  `ad_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '广告图地址',
  `relationship` tinyint(1) NOT NULL DEFAULT '0' COMMENT '关系确定方式0注册确定1消费确定',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id_idx` (`store_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='分销设置表';

-- ----------------------------
-- Records of lkt_distribution_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_distribution_goods
-- ----------------------------
DROP TABLE IF EXISTS `lkt_distribution_goods`;
CREATE TABLE `lkt_distribution_goods` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `store_id` int NOT NULL COMMENT '商城ID',
  `p_id` int NOT NULL COMMENT '商品ID',
  `s_id` int NOT NULL COMMENT '属性ID',
  `pv` decimal(12,2) NOT NULL COMMENT 'pv值',
  `uplevel` int DEFAULT '0' COMMENT '晋升等级\r\n一次性消费满足金额 onebuy \r\n推荐recomm[0]个级别为recomm[1]会员\r\n累计消费满manybuy\r\n累计业绩满manyyeji[0]\r\n直推人数满manypeople[0]个，团队人数满manypeople[1]个',
  `distribution_rule` tinyint(1) NOT NULL DEFAULT '1' COMMENT '分销规则类型 1等级规则 2自定义',
  `rules_set` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '自定义规则设置',
  `add_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '添加时间',
  `recycle` tinyint(1) NOT NULL DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='分销商品表';

-- ----------------------------
-- Records of lkt_distribution_goods
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_distribution_grade
-- ----------------------------
DROP TABLE IF EXISTS `lkt_distribution_grade`;
CREATE TABLE `lkt_distribution_grade` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `sets` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `datetime` timestamp NOT NULL COMMENT '创建时间',
  `is_agent` int DEFAULT '0' COMMENT '是否为代理商',
  `is_ordinary` int DEFAULT '0' COMMENT '是否是普通分销商0 不是 1是',
  `transfer_balance` int DEFAULT '0' COMMENT '推荐后消费金转余额比例',
  `sort` int DEFAULT '1' COMMENT '排序号',
  `discount` decimal(12,2) DEFAULT NULL COMMENT '购物折扣',
  `integral` int DEFAULT '0' COMMENT '积分',
  `member_proportion` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '会员专区佣金比例',
  `member_consumer_money` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '会员专区消费金',
  `uplevel_obj` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '升级条件',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='分销商等级表';

-- ----------------------------
-- Records of lkt_distribution_grade
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_distribution_income
-- ----------------------------
DROP TABLE IF EXISTS `lkt_distribution_income`;
CREATE TABLE `lkt_distribution_income` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'user_id',
  `estimated_income` decimal(10,2) DEFAULT NULL COMMENT '当日预估收益',
  `order_num` int DEFAULT NULL COMMENT '当日有效订单数量',
  `order_price` decimal(10,2) DEFAULT NULL COMMENT '当日订单金额',
  `new_customer` int DEFAULT NULL COMMENT '当日新增客户  新增绑定永久关系',
  `new_invitation` int DEFAULT NULL COMMENT '当日新增邀请 新增绑定临时关系',
  `add_time` datetime DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=58 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='分销系统收益统计报表';

