-- ----------------------------
-- Table structure for lkt_distribution_log
-- ----------------------------
DROP TABLE IF EXISTS `lkt_distribution_log`;
CREATE TABLE `lkt_distribution_log` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `store_id` int NOT NULL COMMENT '商户ID',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `operator` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '操作员',
  `old_value` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '修改前值',
  `new_value` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '修改后值',
  `event` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '事件',
  `add_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='分销用户信息修改日志';

-- ----------------------------
-- Records of lkt_distribution_log
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_distribution_ranking
-- ----------------------------
DROP TABLE IF EXISTS `lkt_distribution_ranking`;
CREATE TABLE `lkt_distribution_ranking` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `store_id` int NOT NULL COMMENT '商城ID',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `zhanghao` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户账号',
  `commission` decimal(12,2) NOT NULL COMMENT '佣金',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '排行类型 1今日2本周3本月4本年',
  `add_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='分佣排行表';

-- ----------------------------
-- Records of lkt_distribution_ranking
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_distribution_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_distribution_record`;
CREATE TABLE `lkt_distribution_record` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '购买员',
  `from_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '分销员',
  `money` decimal(12,2) NOT NULL COMMENT '佣金金额',
  `sNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  `level` int DEFAULT NULL COMMENT '层级',
  `event` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '事件',
  `type` tinyint NOT NULL DEFAULT '0' COMMENT '类型 1:转入(收入) 2:提现 3:个人进获奖8:充值积分9转出',
  `genre` tinyint(1) NOT NULL DEFAULT '1' COMMENT '分佣类型 1直推分佣2间推分佣3平级奖4级差奖',
  `add_date` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `status` int NOT NULL DEFAULT '0' COMMENT '是否发放',
  `user_level` int DEFAULT NULL COMMENT '用户当前分销等级',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='佣金日志表';

-- ----------------------------
-- Records of lkt_distribution_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_distribution_withdraw
-- ----------------------------
DROP TABLE IF EXISTS `lkt_distribution_withdraw`;
CREATE TABLE `lkt_distribution_withdraw` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户id',
  `name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '名称',
  `wx_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '微信id',
  `mobile` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '手机',
  `Bank_id` int DEFAULT NULL COMMENT '银行卡id',
  `money` decimal(12,2) NOT NULL COMMENT '提现金额',
  `z_money` decimal(12,2) DEFAULT NULL COMMENT '剩余金额',
  `s_charge` decimal(12,2) DEFAULT NULL COMMENT '手续费',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 0：审核中 1：审核通过 2：拒绝',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '申请时间',
  `refuse` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '拒绝原因',
  `is_mch` int DEFAULT '0' COMMENT '是否是店铺提现',
  `examine_date` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '提现审核时间',
  `withdraw_status` int NOT NULL DEFAULT '1' COMMENT '提现类型 1银行卡  2微信余额 3贝宝余额',
  `wx_status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '1' COMMENT '提现到微信余额提现状态：1进行中 2已完成 3提现失败',
  `wx_open_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户openid',
  `wx_son` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '微信提现到零钱订单号',
  `wx_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户微信名称',
  `realname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户微信余额提现真实姓名',
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '贝宝提现邮箱',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='提现列表';

-- ----------------------------
-- Records of lkt_distribution_withdraw
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_diy
-- ----------------------------
DROP TABLE IF EXISTS `lkt_diy`;
CREATE TABLE `lkt_diy` (
  `id` int NOT NULL AUTO_INCREMENT,
  `version` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '版本号',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '页面名称',
  `value` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '页面数据',
  `add_time` int DEFAULT NULL COMMENT '添加时间',
  `update_time` int DEFAULT NULL COMMENT '更新时间',
  `status` tinyint(1) DEFAULT '0' COMMENT '是否使用',
  `type` tinyint(1) DEFAULT NULL COMMENT '页面类型',
  `is_del` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  `store_id` int NOT NULL COMMENT '商城ID',
  `cover` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '封面图',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_ID_idx` (`store_id`) USING BTREE,
  KEY `status_idx` (`status`) USING BTREE,
  KEY `is_del_idx` (`is_del`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='DIY数据表';

-- ----------------------------
-- Records of lkt_diy
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_diy_page
-- ----------------------------
DROP TABLE IF EXISTS `lkt_diy_page`;
CREATE TABLE `lkt_diy_page` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '页面id',
  `store_id` int NOT NULL COMMENT '商城id',
  `page_title` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '页面名称',
  `page_type` int NOT NULL COMMENT '页面类型',
  `page_context` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '页面内容',
  `is_show` int NOT NULL DEFAULT '1' COMMENT '状态 1 启用 2 不启用',
  `is_del` int NOT NULL DEFAULT '2' COMMENT '删除 1是 2否',
  `mch_id` int DEFAULT NULL COMMENT '店铺id',
  `sp_id` int DEFAULT NULL COMMENT '供应商id',
  `add_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `update_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- ----------------------------
-- Records of lkt_diy_page
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_diy_project
-- ----------------------------
DROP TABLE IF EXISTS `lkt_diy_project`;
CREATE TABLE `lkt_diy_project` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '项目id',
  `store_id` int NOT NULL COMMENT '商城id',
  `admin_id` int NOT NULL COMMENT '管理员id',
  `pro_title` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '项目名称',
  `industry` tinyblob COMMENT '所属行业',
  `pro_config` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '项目配置',
  `logo` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '项目logo',
  `cover` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '封面',
  `pro_pages` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '页面集合',
  `is_show` int NOT NULL DEFAULT '1' COMMENT '状态 1启用 2不启用',
  `is_del` int NOT NULL DEFAULT '2' COMMENT '删除  1 是 2 否',
  `mch_id` int DEFAULT NULL COMMENT '店铺id',
  `sp_id` int DEFAULT NULL COMMENT '供应商id',
  `add_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `update_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Diy项目配置信息';

-- ----------------------------
-- Records of lkt_diy_project
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_drafts
-- ----------------------------
DROP TABLE IF EXISTS `lkt_drafts`;
CREATE TABLE `lkt_drafts` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `mch_id` int DEFAULT NULL COMMENT '店铺ID',
  `store_id` int DEFAULT NULL COMMENT '商城id',
  `supplier_id` int DEFAULT NULL COMMENT '供应商ID',
  `text` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '草稿数据',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='草稿箱';

-- ----------------------------
-- Records of lkt_drafts
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_ds_country
-- ----------------------------
DROP TABLE IF EXISTS `lkt_ds_country`;
CREATE TABLE `lkt_ds_country` (
  `id` smallint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '英文名称',
  `zh_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '中文名称',
  `code` varchar(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '英文编码',
  `num3` int DEFAULT NULL COMMENT '数字编码',
  `code2` varchar(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'ITU电话代码',
  `is_show` tinyint NOT NULL DEFAULT '1' COMMENT '是否显示 1 显示 0 不显示',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `name` (`name`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=243 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='国家信息';

