-- ----------------------------
-- Table structure for lkt_edition
-- ----------------------------
DROP TABLE IF EXISTS `lkt_edition`;
CREATE TABLE `lkt_edition` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `edition` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '版本号',
  `edition_url` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '路径',
  `type` tinyint NOT NULL DEFAULT '0' COMMENT '是否是热更新 0:是 1:不是',
  `content` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '常规更新',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `appname` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `android_url` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'android下载地址',
  `ios_url` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'ios下载地址',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='版本表';

-- ----------------------------
-- Records of lkt_edition
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_express
-- ----------------------------
DROP TABLE IF EXISTS `lkt_express`;
CREATE TABLE `lkt_express` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id',
  `kuaidi_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '快递名称',
  `type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '简称',
  `is_open` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否开启1开启2关闭',
  `sort` int DEFAULT '1' COMMENT '排序',
  `recycle` tinyint(1) DEFAULT '0' COMMENT '是否回收0显示1不显示',
  `add_date` timestamp NOT NULL COMMENT '添加时间',
  `wx_delivery_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '微信物流公司id',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `id` (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=167 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='快递公司';

