-- ----------------------------
-- Table structure for lkt_express_delivery
-- ----------------------------
DROP TABLE IF EXISTS `lkt_express_delivery`;
CREATE TABLE `lkt_express_delivery` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城ID',
  `sNo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '订单号',
  `order_details_id` int DEFAULT '0' COMMENT '订单详情ID',
  `express_id` int DEFAULT '0' COMMENT '快递公司ID',
  `courier_num` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '快递单号',
  `num` int DEFAULT '0' COMMENT '商品数量',
  `deliver_time` timestamp NULL DEFAULT NULL COMMENT '发货时间',
  `childNum` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '子单号',
  `returnNum` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '回单号',
  `label` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '面单短链',
  `kdComOrderNum` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '快递公司订单号',
  `is_status` tinyint DEFAULT '0' COMMENT '是否打印 0.未打印 1.已打印',
  `subtable_id` int NOT NULL DEFAULT '0' COMMENT '快递公司子表ID',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='快递记录表';

-- ----------------------------
-- Records of lkt_express_delivery
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_express_subtable
-- ----------------------------
DROP TABLE IF EXISTS `lkt_express_subtable`;
CREATE TABLE `lkt_express_subtable` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int DEFAULT '0' COMMENT '商城ID',
  `mch_id` int DEFAULT '0' COMMENT '店铺ID',
  `express_id` int DEFAULT '0' COMMENT '主表ID',
  `partner_id` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '电子面单客户账户或月结账号',
  `partner_key` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '电子面单密码',
  `partner_secret` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '电子面单密钥',
  `partner_name` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '电子面单客户账户名称',
  `express_net` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '收件网点名称',
  `express_code` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '电子面单承载编号',
  `check_man` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '电子面单承载快递员名',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `recovery` tinyint DEFAULT '0' COMMENT '是否删除 0.未删除 1.已删除',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='快递公司子表';

-- ----------------------------
-- Records of lkt_express_subtable
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_extension
-- ----------------------------
DROP TABLE IF EXISTS `lkt_extension`;
CREATE TABLE `lkt_extension` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` char(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '商城id',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '名称',
  `image` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '图片路径',
  `sort` char(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '100' COMMENT '排序号',
  `x` char(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT 'x坐标',
  `y` char(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT 'y坐标',
  `add_date` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `kuan` int NOT NULL DEFAULT '150' COMMENT '二维码宽度',
  `type` int NOT NULL COMMENT '海报类型 1.文章海报 2.红包海报 3.商品海报 4.分销海报 5.邀请海报 6.竞拍海报',
  `keyword` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '关键词',
  `url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '链接地址',
  `isdefault` int DEFAULT '0' COMMENT '是否默认',
  `bg` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '背景图片',
  `color` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '颜色',
  `waittext` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '等待语',
  `data` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '排序的数据',
  `store_type` tinyint DEFAULT '1' COMMENT '来源 1.小程序 2.app',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='推广图片表';

-- ----------------------------
-- Records of lkt_extension
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_file_delivery
-- ----------------------------
DROP TABLE IF EXISTS `lkt_file_delivery`;
CREATE TABLE `lkt_file_delivery` (
  `id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'id',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '文件名称',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '标签副标题',
  `upload_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '文件上传路径',
  `status` int NOT NULL DEFAULT '0' COMMENT '文件状态 1=发货成功 0=发货失败',
  `text` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '失败原因',
  `is_del` int DEFAULT NULL COMMENT '是否删除标识',
  `mch_id` int DEFAULT NULL COMMENT '操作店铺id',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '发货时间',
  `update_date` timestamp NULL DEFAULT NULL,
  `type` int DEFAULT '0' COMMENT '0导入上传商品  1批量发货',
  `order_num` int DEFAULT NULL COMMENT '发货订单数量/导入商品数',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='批量发货表';

-- ----------------------------
-- Records of lkt_file_delivery
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_files_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_files_record`;
CREATE TABLE `lkt_files_record` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `store_id` char(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '商城id',
  `store_type` char(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '平台类型',
  `group` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '分组',
  `upload_mode` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '上传方式 1:本地 2:阿里云 3:腾讯云 4:七牛云 5.minio',
  `image_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '图片名称',
  `add_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `mch_id` int DEFAULT NULL COMMENT '店铺ID',
  `recycle` tinyint(1) NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.回收',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '标题',
  `explain` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '说明，图片信息',
  `alternative_text` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '替代文本',
  `describe` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '图像描述',
  `supplier_id` int DEFAULT NULL COMMENT '供应商id',
  `type` int NOT NULL DEFAULT '1' COMMENT '资源类型，1图片，2视频',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户自定义的名称',
  `add_user` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '上传人',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `recycle` (`recycle`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `mch_id` (`mch_id`) USING BTREE,
  KEY `image_name_index` (`image_name`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=23148 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='上传文件记录表';

