-- ----------------------------
-- Table structure for lkt_finance_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_finance_config`;
CREATE TABLE `lkt_finance_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `plug_ins_id` int NOT NULL DEFAULT '0' COMMENT '插件id',
  `min_cz` decimal(12,2) DEFAULT NULL COMMENT '最小充值金额',
  `min_amount` decimal(12,2) NOT NULL COMMENT '最少提现金额',
  `max_amount` decimal(12,2) NOT NULL COMMENT '最大提现金额',
  `service_charge` decimal(12,3) NOT NULL COMMENT '手续费',
  `unit` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '元' COMMENT '小程序钱包单位',
  `modify_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `multiple` int DEFAULT '0' COMMENT '提现倍数',
  `transfer_multiple` int DEFAULT '0' COMMENT '转账倍数',
  `cz_multiple` int DEFAULT '100' COMMENT '充值倍数',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='钱包配置表';

-- ----------------------------
-- Records of lkt_finance_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_flashsale_activity
-- ----------------------------
DROP TABLE IF EXISTS `lkt_flashsale_activity`;
CREATE TABLE `lkt_flashsale_activity` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int NOT NULL COMMENT '商城id',
  `goods_id` int NOT NULL COMMENT '商品id',
  `label_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动id',
  `flashsale_price` decimal(11,2) NOT NULL DEFAULT '0.00' COMMENT '折扣价格',
  `price_type` int NOT NULL DEFAULT '0' COMMENT '价格单位 0=百分比 1=固定值',
  `discount` decimal(10,2) DEFAULT NULL COMMENT '折扣',
  `buylimit` int DEFAULT NULL COMMENT '购买上限',
  `num` int NOT NULL DEFAULT '0' COMMENT '活动库存',
  `max_num` int DEFAULT NULL COMMENT '最大数量',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '活动名称',
  `status` int NOT NULL DEFAULT '1' COMMENT '活动状态 1 未开始 2 进行中 3结束',
  `type` tinyint(1) DEFAULT NULL COMMENT '活动类型',
  `starttime` datetime NOT NULL COMMENT '活动开始时间',
  `endtime` datetime NOT NULL COMMENT '活动结束时间',
  `isshow` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否显示 1 是 0 否',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 1 是 0 否',
  `create_date` datetime DEFAULT NULL COMMENT '创建时间',
  `update_date` datetime DEFAULT NULL COMMENT '修改时间',
  `is_notice` int NOT NULL DEFAULT '0' COMMENT '是否通知 0=未通知 1=已通知',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='限时折扣活动表';

-- ----------------------------
-- Records of lkt_flashsale_activity
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_flashsale_addgoods
-- ----------------------------
DROP TABLE IF EXISTS `lkt_flashsale_addgoods`;
CREATE TABLE `lkt_flashsale_addgoods` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0',
  `goods_id` int NOT NULL COMMENT '商品ID',
  `attr_id` int DEFAULT NULL COMMENT '属性id',
  `goods_price` decimal(11,2) NOT NULL COMMENT '商品价格',
  `price` decimal(11,2) NOT NULL COMMENT '加购价格',
  `num` int NOT NULL DEFAULT '0' COMMENT '库存数量',
  `max_num` int NOT NULL DEFAULT '0' COMMENT '上架库存',
  `sort` int NOT NULL DEFAULT '1' COMMENT '排序',
  `is_delete` int NOT NULL DEFAULT '0' COMMENT '是否删除:0否   1是',
  `add_time` datetime DEFAULT NULL COMMENT '添加时间',
  `update_time` datetime DEFAULT NULL COMMENT '修改时间',
  `status` int NOT NULL DEFAULT '1' COMMENT '上架状态 1待上架， 2已上架 ， 3已下架',
  `mch_id` int NOT NULL DEFAULT '0' COMMENT '店铺ID',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='限时折扣加购商品表';

-- ----------------------------
-- Records of lkt_flashsale_addgoods
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_flashsale_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_flashsale_config`;
CREATE TABLE `lkt_flashsale_config` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键自增',
  `store_id` int NOT NULL COMMENT '商城id',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启 1 是 0 否',
  `order_after` int NOT NULL DEFAULT '604800' COMMENT '订单售后时间 (单位秒)',
  `auto_the_goods` int NOT NULL DEFAULT '7' COMMENT '自动收货时间',
  `auto_good_comment_day` int NOT NULL DEFAULT '0' COMMENT '自动评价设置几后自动好评',
  `auto_good_comment_content` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '好评内容',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `good_switch` tinyint NOT NULL DEFAULT '0' COMMENT '自动评价设置 0.关闭 1.开启',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='限时折扣设置';

-- ----------------------------
-- Records of lkt_flashsale_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_flashsale_label
-- ----------------------------
DROP TABLE IF EXISTS `lkt_flashsale_label`;
CREATE TABLE `lkt_flashsale_label` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int DEFAULT NULL,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动名称',
  `status` int DEFAULT '1' COMMENT '活动状态 1 未开始 2 进行中 3结束',
  `discount` decimal(10,2) DEFAULT NULL COMMENT '折扣',
  `buylimit` int DEFAULT NULL COMMENT '购买上限',
  `is_show` int NOT NULL DEFAULT '0',
  `starttime` timestamp NULL DEFAULT NULL COMMENT '活动开始时间',
  `endtime` timestamp NULL DEFAULT NULL COMMENT '活动结束时间',
  `sort` int DEFAULT NULL COMMENT '序号',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动说明',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `update_date` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `recovery` int DEFAULT '0' COMMENT '是否回收  0未回收  1已回收',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `update_source` int NOT NULL DEFAULT '1' COMMENT '最后的更新来源 1为h5商家 2为pc店铺',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='限时折扣活动表';

-- ----------------------------
-- Records of lkt_flashsale_label
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_flashsale_pro
-- ----------------------------
DROP TABLE IF EXISTS `lkt_flashsale_pro`;
CREATE TABLE `lkt_flashsale_pro` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int NOT NULL COMMENT '商城id',
  `activity_id` int NOT NULL COMMENT '插件活动id',
  `goods_id` int DEFAULT NULL COMMENT '商品ID',
  `attr_id` int DEFAULT '0' COMMENT '规格id',
  `num` int NOT NULL DEFAULT '0' COMMENT '活动库存',
  `max_num` int DEFAULT NULL COMMENT '最大数量',
  `add_time` datetime NOT NULL COMMENT '添加日期',
  `is_delete` int NOT NULL DEFAULT '0' COMMENT '是否删除 1 是 0 否',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='限时折扣商品表';

-- ----------------------------
-- Records of lkt_flashsale_pro
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_flashsale_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_flashsale_record`;
CREATE TABLE `lkt_flashsale_record` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int NOT NULL COMMENT '店铺id',
  `user_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户id',
  `activity_id` int NOT NULL DEFAULT '0' COMMENT '活动id',
  `time_id` int NOT NULL DEFAULT '0' COMMENT '时段id',
  `pro_id` int NOT NULL DEFAULT '0' COMMENT '商品id',
  `attr_id` int NOT NULL DEFAULT '0' COMMENT '规格id',
  `sec_id` int NOT NULL DEFAULT '0' COMMENT '限时折扣id',
  `price` decimal(11,2) NOT NULL COMMENT '价格',
  `num` int NOT NULL DEFAULT '0' COMMENT '数量',
  `sNo` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '限时折扣订单',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 1是 0否',
  `add_time` datetime NOT NULL COMMENT '添加日期',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='限时折扣记录表';

-- ----------------------------
-- Records of lkt_flashsale_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_freight
-- ----------------------------
DROP TABLE IF EXISTS `lkt_freight`;
CREATE TABLE `lkt_freight` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `name` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '名称',
  `type` tinyint NOT NULL DEFAULT '0' COMMENT '类型 0:件 1:重量',
  `freight` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '指定运费',
  `is_default` tinyint NOT NULL DEFAULT '0' COMMENT '类型 0:不默认 1:默认',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `mch_id` int NOT NULL DEFAULT '0' COMMENT '店铺id',
  `is_package_settings` int DEFAULT '0' COMMENT '是否是包邮设置 0.未开启 1.开启',
  `package_settings` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '包邮设置',
  `is_no_delivery` int DEFAULT '0' COMMENT '是否不配送 0.未开启 1.开启',
  `no_delivery` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '不配送地区',
  `supplier_id` int DEFAULT NULL COMMENT '供应商id',
  `default_freight` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '默认运费',
  `threeIdsList` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '不配送地区ID',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `mch_id` (`mch_id`) USING BTREE,
  KEY `name` (`name`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='运费表';

-- ----------------------------
-- Records of lkt_freight
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_go_group_order
-- ----------------------------
DROP TABLE IF EXISTS `lkt_go_group_order`;
CREATE TABLE `lkt_go_group_order` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户id',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '姓名',
  `mobile` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '联系电话',
  `num` int DEFAULT NULL COMMENT '数量',
  `z_price` decimal(12,2) DEFAULT NULL COMMENT '总价',
  `sNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  `sheng` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '省',
  `shi` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '市',
  `xian` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '县',
  `address` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '详细地址',
  `remark` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户备注',
  `pay` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '支付方式',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `pay_time` timestamp NULL DEFAULT NULL COMMENT '支付时间',
  `arrive_time` timestamp NULL DEFAULT NULL COMMENT '到货时间',
  `status` tinyint DEFAULT '0' COMMENT '状态 0:未付款 1:未发货 2:待收货 3:待评论 4:退货 5:已完成 6:订单失效 7:订单  关闭 8:删除订单 9:拼团中 10:拼团失败-未退款 11:拼团失败-已退款',
  `coupon_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '优惠券id',
  `subtraction_id` int DEFAULT NULL COMMENT '满减活动ID',
  `consumer_money` int DEFAULT '0' COMMENT '消费金',
  `coupon_activity_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '满减活动名称',
  `drawid` int DEFAULT '0' COMMENT '活动ID',
  `otype` char(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '订单类型',
  `ptcode` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '拼团编号',
  `pid` char(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拼团订单类型:kaituan开团 cantuan参团',
  `ptstatus` smallint DEFAULT NULL COMMENT '拼团状态:0,未付款 1,拼团中 2,拼团成功 3,拼团失败',
  `groupman` char(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拼团人数',
  `refundsNo` char(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '拼团退款单号',
  `trade_no` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '微信支付单号',
  `is_anonymous` int DEFAULT '0' COMMENT '是否匿名(0,否  1.是',
  `logistics_service` int DEFAULT NULL COMMENT '物流服务',
  `overall_evaluation` int DEFAULT NULL COMMENT '总体评价',
  `spz_price` decimal(10,2) DEFAULT NULL COMMENT '商品总价',
  `reduce_price` decimal(10,2) DEFAULT NULL COMMENT '查询出的满减金额',
  `coupon_price` decimal(10,2) DEFAULT NULL COMMENT '查询出的优惠券金额',
  `red_packet` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '红包金额',
  `allow` int DEFAULT '0' COMMENT '积分',
  `parameter` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '参数',
  `source` tinyint NOT NULL DEFAULT '1' COMMENT '来源 1.小程序 2.app',
  `delivery_status` int DEFAULT '0' COMMENT '提醒发货',
  `readd` int NOT NULL DEFAULT '0' COMMENT '是否已读（0，未读  1 已读）',
  `remind` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '提醒\r\n\r\n发货时间间隔',
  `offset_balance` decimal(10,2) DEFAULT NULL COMMENT '抵扣余额',
  `mch_id` varchar(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '店铺ID',
  `zhekou` decimal(10,2) NOT NULL COMMENT '分销折扣',
  `grade_rate` decimal(10,2) DEFAULT NULL COMMENT '会员等级折扣',
  `grade_score` int DEFAULT NULL COMMENT '会员购物积分',
  `grade_fan` decimal(12,2) DEFAULT NULL COMMENT '会员返现金额',
  `p_sNo` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '父类订单号',
  `activity_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '活动id',
  `bargain_id` int NOT NULL DEFAULT '0' COMMENT '砍价活动id',
  `comm_discount` decimal(10,2) NOT NULL COMMENT '分销折扣',
  `real_sno` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '调起支付所用订单号',
  `remarks` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '订单备注',
  `self_lifting` tinyint DEFAULT '0' COMMENT '自提 0.配送 1.自提',
  `extraction_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '提现码',
  `extraction_code_img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '提现码二维码',
  `is_put` tinyint DEFAULT '0' COMMENT '是否发放佣金 0.否 1.是',
  `z_freight` decimal(12,2) DEFAULT NULL COMMENT '总运费',
  `preferential_amount` decimal(12,2) DEFAULT NULL COMMENT '优惠金额',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.回收',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `user_id` (`user_id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `sNo` (`sNo`(191)) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='拼团订单记录表';

-- ----------------------------
-- Records of lkt_go_group_order
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_go_group_order_details
-- ----------------------------
DROP TABLE IF EXISTS `lkt_go_group_order_details`;
CREATE TABLE `lkt_go_group_order_details` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int DEFAULT '0' COMMENT '商城id',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户id',
  `p_id` int DEFAULT NULL COMMENT '产品id',
  `p_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '产品名称',
  `p_price` decimal(12,2) DEFAULT NULL COMMENT '产品价格',
  `num` int DEFAULT NULL COMMENT '数量',
  `unit` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '单位',
  `r_sNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `deliver_time` timestamp NULL DEFAULT NULL COMMENT '发货时间',
  `arrive_time` timestamp NULL DEFAULT NULL COMMENT '到货时间',
  `r_status` tinyint DEFAULT '0' COMMENT ' ''状态 0：未付款 1：未发货 2：待收货 3：待评论 4：退货 5:已完成 6 订单关闭 9拼团中 10 拼团失败-未退款 11 拼团失败-已退款''',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '退货原因',
  `reason` char(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'app退款原因',
  `re_type` tinyint DEFAULT '0' COMMENT '退款类型 1:退货退款  2:退款 3:售后',
  `re_apply_money` float(12,2) DEFAULT NULL COMMENT '用户申请退款金额',
  `re_money` float(12,2) DEFAULT NULL COMMENT '退款金额',
  `real_money` decimal(12,2) DEFAULT NULL COMMENT '实际退款金额',
  `re_time` datetime DEFAULT NULL COMMENT '申请退款时间',
  `re_photo` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '上传凭证',
  `audit_time` datetime DEFAULT NULL COMMENT '审核时间',
  `r_content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '拒绝原因',
  `r_type` tinyint DEFAULT '100' COMMENT '类型 100:不在退货退款状态0:审核中 1:同意并让用户寄回 2:拒绝(退货退款) 3:用户已快递 4:收到寄回商品,同意并退款 5：拒绝并退回商品 8:拒绝(退款) 9:同意并退款 10:拒绝(售后)11:同意并且寄回商品 12售后结束',
  `express_id` int DEFAULT NULL COMMENT '快递公司id',
  `courier_num` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '快递单号',
  `express_type` tinyint DEFAULT '1' COMMENT '发货类型 1.手动发货 2.自动发货',
  `freight` decimal(12,2) DEFAULT NULL COMMENT '运费',
  `size` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '配置名称',
  `sid` char(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '规格属性id',
  `invoice` tinyint DEFAULT '0' COMMENT '发货单打印 0.否 1.是',
  `express` tinyint DEFAULT '0' COMMENT '快递单打印 0.否 1.是',
  `exchange_num` int DEFAULT '0' COMMENT '换货次数',
  `coupon_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '优惠券id',
  `after_discount` decimal(12,2) DEFAULT NULL COMMENT '优惠后的金额',
  `settlement_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '订单结算标识 0未结算 1已结算',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.回收',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `user_id` (`user_id`) USING BTREE,
  KEY `r_sNo` (`r_sNo`(191)) USING BTREE,
  KEY `sid` (`sid`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='拼团订单详情表';

-- ----------------------------
-- Records of lkt_go_group_order_details
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_group_activity
-- ----------------------------
DROP TABLE IF EXISTS `lkt_group_activity`;
CREATE TABLE `lkt_group_activity` (
  `id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动id',
  `name` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动名称',
  `store_id` int NOT NULL COMMENT '商城id',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `status` int NOT NULL DEFAULT '0' COMMENT '拼团状态 0=未开始 1=拼团中 2=已结束',
  `start_date` timestamp NOT NULL COMMENT '开始时间',
  `end_date` timestamp NOT NULL COMMENT '结束时间',
  `is_custom` int NOT NULL DEFAULT '0' COMMENT '时间是否自定义 0不是 1是',
  `team_rule` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '团长参团规则json [{man:1,canDiscount:8,openDiscount:75},{man:2,canDiscount:7,openDiscount:55}]',
  `team_limit` int NOT NULL DEFAULT '0' COMMENT '团长是否可参团',
  `goods_limit` int NOT NULL DEFAULT '0' COMMENT '同一商品参团限制开关',
  `is_show` int NOT NULL DEFAULT '1' COMMENT '是否显示',
  `add_date` timestamp NOT NULL COMMENT '添加时间',
  `recycle` int NOT NULL DEFAULT '0' COMMENT '删除标识',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='拼团活动表';

-- ----------------------------
-- Records of lkt_group_activity
-- ----------------------------
BEGIN;
COMMIT;

