-- ----------------------------
-- Table structure for lkt_group_product
-- ----------------------------
DROP TABLE IF EXISTS `lkt_group_product`;
CREATE TABLE `lkt_group_product` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `group_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动标题',
  `attr_id` int NOT NULL COMMENT '规格id',
  `product_id` int unsigned DEFAULT NULL COMMENT '产品id',
  `group_level` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '拼团等级价格参数',
  `group_data` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '拼团参数数据',
  `starttime` timestamp NULL DEFAULT NULL COMMENT '开始日期',
  `endtime` timestamp NULL DEFAULT NULL COMMENT '结束日期',
  `activity_no` int NOT NULL COMMENT '活动编号',
  `g_status` tinyint NOT NULL DEFAULT '1' COMMENT '活动状态: 1.未开始 2.活动中 3.已结束',
  `is_show` tinyint NOT NULL DEFAULT '1' COMMENT '是否显示',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_copy` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为复制 1为复制 0不是复制',
  `platform_activities_id` int NOT NULL DEFAULT '0' COMMENT '平台活动id',
  `mch_id` int NOT NULL DEFAULT '0' COMMENT '店铺id',
  `audit_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '审核状态',
  `reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '审核失败原因',
  `num` int DEFAULT '0' COMMENT '活动库存',
  `sales_volume` int DEFAULT '0' COMMENT '活动销量',
  `price` decimal(12,2) DEFAULT NULL COMMENT '成本价',
  `addtime` datetime NOT NULL COMMENT '申请时间',
  `free_freight` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否免邮(1 是 0 否)默认0',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='拼团产品';

