  `bg` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '小图标',
  `level` int NOT NULL COMMENT '级别',
  `sort` int DEFAULT '100' COMMENT '排序',
