-- ----------------------------
-- Table structure for lkt_integral_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_integral_config`;
CREATE TABLE `lkt_integral_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `bg_img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `status` int NOT NULL DEFAULT '0' COMMENT '插件状态 0关闭 1开启',
  `score_ratio` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '积分支付比例',
  `same_piece` int DEFAULT NULL COMMENT '同件n件包邮',
  `package_settings` int NOT NULL DEFAULT '0' COMMENT '多件包邮设置 0.未开启 1.开启',
  `order_failure` int NOT NULL DEFAULT '0' COMMENT '订单失效 (单位 秒)',
  `order_after` int NOT NULL DEFAULT '604800' COMMENT '订单售后时间 (单位秒)',
  `auto_the_goods` int NOT NULL DEFAULT '604800' COMMENT '自动收货时间',
  `deliver_remind` int NOT NULL DEFAULT '3600' COMMENT '提醒发货限制 间隔(单位 秒)',
  `auto_good_comment_day` int NOT NULL DEFAULT '0' COMMENT '自动评价设置几后自动好评',
  `proportion` decimal(10,0) DEFAULT NULL COMMENT '积分比例(购物赠送积分=购物交易金额*赠送比例)',
  `give_status` int DEFAULT '0' COMMENT '发放状态(0=收货后 1=付款后)',
  `overdue_time` int DEFAULT '604800' COMMENT '积分有效时间从积分获取后开始计算，至 x 失效',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `ams_time` int DEFAULT '0' COMMENT '收货后多少天返回积分，至 x 失效',
  `auto_good_comment_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '自动评价内容',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='分销设置表';

-- ----------------------------
-- Records of lkt_integral_config
-- ----------------------------
BEGIN;
COMMIT;

