  `is_delete` smallint NOT NULL DEFAULT '0' COMMENT '是否删除:0否   1是',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `update_time` timestamp NULL DEFAULT NULL COMMENT '修改时间',
