-- ----------------------------
-- Table structure for lkt_invoice_info
-- ----------------------------
DROP TABLE IF EXISTS `lkt_invoice_info`;
CREATE TABLE `lkt_invoice_info` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `user_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户id',
  `type` int NOT NULL DEFAULT '1' COMMENT '抬头类型 1.企业 2.个人',
  `company_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '公司名称(抬头名称)',
  `company_tax_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '公司税号',
  `invoice_header` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '发票抬头快照',
  `s_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单号',
  `invoice_amount` decimal(10,2) NOT NULL COMMENT '发票金额',
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '电子邮箱',
  `invoice_status` int NOT NULL DEFAULT '1' COMMENT '发票状态 1.申请中 2.已完成 3.已撤销',
  `file` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '发票文件',
  `file_time` timestamp NULL DEFAULT NULL COMMENT '上传发票文件时间',
  `recovery` int NOT NULL DEFAULT '0' COMMENT '是否回收 0.否 1.是',
  `add_time` timestamp NOT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='发票信息表';

-- ----------------------------
-- Records of lkt_invoice_info
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_jump_path
-- ----------------------------
DROP TABLE IF EXISTS `lkt_jump_path`;
CREATE TABLE `lkt_jump_path` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int DEFAULT '0' COMMENT '商城ID',
  `type0` tinyint DEFAULT '0' COMMENT '跳转类型 1.分类 2.商品 3.店铺',
  `type` tinyint NOT NULL DEFAULT '1' COMMENT '类型 1.移动端 2.PC商城',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '标题',
  `url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '路径',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '是否启用 0.不开启 1.开启',
  `parameter_status` tinyint NOT NULL DEFAULT '0' COMMENT '是否有参数 0.没有参数 1.有参数',
  `parameter` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '参数',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `sid` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '上级id',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='路径跳转表';

-- ----------------------------
-- Records of lkt_jump_path
-- ----------------------------
BEGIN;
COMMIT;

