-- ----------------------------
-- Table structure for lkt_living_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_living_config`;
CREATE TABLE `lkt_living_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '配置id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `is_open` int NOT NULL DEFAULT '0' COMMENT ' 获取是否开启插件 0-不开启 1-开启',
  `mch_is_open` int NOT NULL DEFAULT '0' COMMENT '店铺端入口设置 0-不开启 1-开启',
  `push_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '推流地址',
  `play_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '播放地址',
  `agree_title` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '协议标题',
  `agree_content` text CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '协议内容',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `recycle` int NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.系统回收 2用户回收 3店铺回收',
  `license_key` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '腾讯云直播播放器的key',
  `license_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT '腾讯云直播播放器的url',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='直播配置';

