-- ----------------------------
-- Table structure for lkt_living_product
-- ----------------------------
DROP TABLE IF EXISTS `lkt_living_product`;
CREATE TABLE `lkt_living_product` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '商品id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `living_id` int NOT NULL COMMENT '直播间id',
  `pro_id` int NOT NULL COMMENT '产品id',
  `config_id` int NOT NULL COMMENT '规格id',
  `live_price` decimal(12,2) NOT NULL COMMENT '直播价格',
  `num` int NOT NULL DEFAULT '0' COMMENT '数量',
  `sort` int NOT NULL DEFAULT '1' COMMENT '是否置顶，1为未置顶，0为置顶',
  `xl_num` int NOT NULL DEFAULT '0' COMMENT '销量',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `recycle` int NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.系统回收 2用户回收 3店铺回收',
  `represent` int NOT NULL DEFAULT '0' COMMENT '是否在讲解（每个直播间只能有一个讲解的产品，默认0不讲解）',
  `sort_num` int NOT NULL DEFAULT '0' COMMENT '序号',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='直播间产品';

-- ----------------------------
-- Records of lkt_living_product
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_living_room
-- ----------------------------
DROP TABLE IF EXISTS `lkt_living_room`;
CREATE TABLE `lkt_living_room` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `living_theme` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '直播的标题',
  `living_description` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '直播简介',
  `start_time` timestamp NULL DEFAULT NULL COMMENT '直播开始时间',
  `living_time` char(15) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '直播时长 分钟',
  `end_time` timestamp NULL DEFAULT NULL COMMENT '直播结束时间',
  `living_status` int NOT NULL DEFAULT '0' COMMENT '直播的状态，0：预约中，1：直播中，2：已结束，3：已取消',
  `living_img` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '直播间封面图地址',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `user_id` varchar(15) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '主播用户id',
  `living_num` int NOT NULL DEFAULT '0' COMMENT '直播间观看人数',
  `living_review_num` int NOT NULL DEFAULT '0' COMMENT '直播间评论数',
  `push_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT '' COMMENT '直播间推流地址',
  `play_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '播放地址',
  `like_num` int NOT NULL DEFAULT '0' COMMENT '点赞数',
  `recycle` int NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.系统回收 2用户回收 3店铺回收',
  `sort` int NOT NULL DEFAULT '0' COMMENT '排序',
  `living_fans_num` int NOT NULL DEFAULT '0' COMMENT '观看粉丝数',
  `fans_num` int NOT NULL DEFAULT '0' COMMENT '新增粉丝数',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='直播间';

-- ----------------------------
-- Records of lkt_living_room
-- ----------------------------
BEGIN;
COMMIT;

