-- ----------------------------
-- Table structure for lkt_mch
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch`;
CREATE TABLE `lkt_mch` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户id',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺名称',
  `shop_information` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '店铺信息',
  `shop_range` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '经营范围',
  `realname` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '真实姓名',
  `ID_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '身份证号码',
  `tel` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '联系电话',
  `sheng` char(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `shi` char(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `xian` char(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '联系地址',
  `logo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺Logo',
  `shop_nature` tinyint NOT NULL DEFAULT '0' COMMENT '店铺性质：0.个人 1.企业',
  `business_license` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '营业执照',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '申请时间',
  `review_time` timestamp NULL DEFAULT NULL COMMENT '审核时间',
  `review_status` tinyint NOT NULL DEFAULT '0' COMMENT '审核状态：0.待审核 1.审核通过 2.审核不通过',
  `review_result` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拒绝理由',
  `integral_money` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '商户积分',
  `account_money` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '商户余额',
  `collection_num` int DEFAULT '0' COMMENT '收藏数量',
  `is_open` tinyint(1) NOT NULL DEFAULT '2' COMMENT '是否营业：0.未营业 1.营业中 2.打烊',
  `is_lock` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否被系统关闭：0.否 1.是',
  `confines` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺经营范围',
  `mch_service` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '店铺客服',
  `business_hours` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '营业时间',
  `roomid` int unsigned DEFAULT '0',
  `old_roomid` int DEFAULT '0' COMMENT '旧房间ID',
  `longitude` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '经度',
  `latitude` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '纬度',
  `cashable_money` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '可取现金额',
  `recovery` tinyint NOT NULL DEFAULT '0' COMMENT '是否回收 0.未回收 1.回收',
  `is_invoice` int NOT NULL DEFAULT '0' COMMENT '是否支持开票 0.否 1.是',
  `cid` int NOT NULL DEFAULT '0' COMMENT '分类id',
  `poster_img` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺新增宣传图',
  `head_img` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '店铺头像',
  `collection_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '收款码',
  `pc_mch_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'pc店铺地址',
  `is_open_coupon` int DEFAULT '1' COMMENT '是否开启店铺主页领卷人口',
  `last_login_time` timestamp NULL DEFAULT NULL COMMENT '最后登录时间',
  `sub_mch_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '子商户号',
  `sub_app_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '子商户应用id',
  `is_self_delivery` int NOT NULL DEFAULT '0' COMMENT '是否支持商家自配 0.否 1.是',
  `new_user_order_num` int DEFAULT '0' COMMENT '新增下单客户数',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商户';

-- ----------------------------
-- Records of lkt_mch
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_account_log
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_account_log`;
CREATE TABLE `lkt_mch_account_log` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺id',
  `integral` int DEFAULT '0' COMMENT '积分',
  `integral_money` decimal(12,0) DEFAULT NULL COMMENT '商户积分',
  `price` decimal(12,2) NOT NULL COMMENT '金额',
  `account_money` decimal(12,2) NOT NULL COMMENT '商户余额',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：1.入账 2.出账',
  `type` tinyint NOT NULL DEFAULT '1' COMMENT '类型：1.订单 2.退款 3.提现 4.保证金 5.供应商订单',
  `addtime` timestamp NULL DEFAULT NULL COMMENT '时间',
  `remake` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='入驻商户账户收支记录表';

-- ----------------------------
-- Records of lkt_mch_account_log
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_admin
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_admin`;
CREATE TABLE `lkt_mch_admin` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int DEFAULT '0' COMMENT '商城ID',
  `mch_id` int DEFAULT '0' COMMENT '店铺ID',
  `mch_store_id` int DEFAULT '0' COMMENT '店铺门店ID',
  `ip` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT 'IP',
  `access_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '授权id',
  `account_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '账号',
  `password` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '密码',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `recycle` tinyint(1) DEFAULT '0' COMMENT '回收站 0:不回收 1:回收 ',
  `last_time` timestamp NULL DEFAULT NULL COMMENT '最后一次登录时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺管理员';

-- ----------------------------
-- Records of lkt_mch_admin
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_admin_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_admin_record`;
CREATE TABLE `lkt_mch_admin_record` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int DEFAULT '0' COMMENT '商城ID',
  `administrators_id` int DEFAULT '0' COMMENT '管理员ID',
  `sNo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '订单号',
  `add_date` datetime DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺管理员核销记录表';

-- ----------------------------
-- Records of lkt_mch_admin_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_browse
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_browse`;
CREATE TABLE `lkt_mch_browse` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺id',
  `token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'token',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户id',
  `event` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '事件',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `user_id` (`user_id`) USING BTREE,
  KEY `mch_id` (`mch_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺浏览记录表';

-- ----------------------------
-- Records of lkt_mch_browse
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_buy_power
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_buy_power`;
CREATE TABLE `lkt_mch_buy_power` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '店铺购买力id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `user_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户id',
  `money` decimal(10,2) NOT NULL COMMENT '金额',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `recycle` int NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.系统回收 2用户回收 3店铺回收',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺购买力表';

-- ----------------------------
-- Records of lkt_mch_buy_power
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_class
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_class`;
CREATE TABLE `lkt_mch_class` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL COMMENT '商城id',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '名称',
  `img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '图片',
  `sort` int NOT NULL COMMENT '排序值',
  `is_display` int NOT NULL DEFAULT '0' COMMENT '是否显示 0.否  1.是',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0:正常 1:回收',
  `add_date` timestamp NOT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺分类表';

-- ----------------------------
-- Records of lkt_mch_class
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_config`;
CREATE TABLE `lkt_mch_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `logo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺默认logo',
  `settlement` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '结算方式',
  `min_charge` decimal(12,2) DEFAULT NULL COMMENT '最低提现金额\r\n\r\n',
  `max_charge` decimal(12,2) DEFAULT NULL COMMENT '最大提现金额\r\n\r\n',
  `service_charge` decimal(12,3) DEFAULT NULL COMMENT '手续费',
  `illustrate` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '提现说明',
  `agreement` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '入驻协议',
  `delete_settings` int DEFAULT '0' COMMENT '删除设置',
  `commodity_setup` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '商品设置  1.上传商品 2.\r\n\r\n自选商品',
  `is_display` tinyint DEFAULT '1' COMMENT '是否显示 0.不显示 1.显示',
  `promise_switch` int NOT NULL DEFAULT '0' COMMENT '保证金开关',
  `promise_amt` decimal(10,2) DEFAULT NULL COMMENT '保证金金额',
  `promise_text` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '保证金说明',
  `package_settings` int DEFAULT '0' COMMENT '包邮设置',
  `same_piece` int DEFAULT '0' COMMENT '同件',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `same_order` int DEFAULT '0' COMMENT '同单',
  `poster_img` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺新增宣传图',
  `head_img` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺头像',
  `auto_examine` int NOT NULL DEFAULT '1' COMMENT '店铺自动审核天数',
  `auto_log_off` int NOT NULL DEFAULT '0' COMMENT '自动注销时间(月)',
  `withdrawal_time_open` int NOT NULL DEFAULT '0' COMMENT '提现时间开关 0.不限制 1.指定日期 2.指定时间段',
  `withdrawal_time` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '指定时间(时间段:15-20)',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商户配置表';

-- ----------------------------
-- Records of lkt_mch_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_distribution
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_distribution`;
CREATE TABLE `lkt_mch_distribution` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `d_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分账接收方类型 MERCHANT_ID：商户号  PERSONAL_OPENID：个人openid（由父商户APPID转换得到） PERSONAL_SUB_OPENID: 个人sub_openid（由子商户APPID转换得到）',
  `account` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分账接收方账号',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '分账接收方全称',
  `relationship` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分账接收方关系 SERVICE_PROVIDER：服务商 STORE：门店 STAFF：员工 STORE_OWNER：店主 PARTNER：合作伙伴 HEADQUARTER：总部 BRAND：品牌方 DISTRIBUTOR：分销商 USER：用户 SUPPLIER： 供应商 CUSTOM：自定义',
  `proportion` decimal(12,2) NOT NULL COMMENT '分账比例',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `isAccounts` int DEFAULT NULL COMMENT '是否分账',
  `accountsSet` int DEFAULT NULL COMMENT '分账账号',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺分账账户信息';

-- ----------------------------
-- Records of lkt_mch_distribution
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_distribution_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_distribution_record`;
CREATE TABLE `lkt_mch_distribution_record` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `sub_mch_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '子商户id',
  `account` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分账接收方账号',
  `order_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单号(自己)',
  `wx_order_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单号(微信)',
  `out_order_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分账单号',
  `total_amount` decimal(12,2) NOT NULL COMMENT '分账总金额',
  `amount` decimal(12,2) NOT NULL COMMENT '分账金额',
  `proportion` decimal(12,2) DEFAULT NULL COMMENT '分账比例',
  `r_type` int NOT NULL COMMENT '记录类型 1.分账 2.回退',
  `add_date` datetime DEFAULT NULL COMMENT '添加时间',
  `is_platform_account` tinyint DEFAULT '0' COMMENT '是否是平台 0.不是 1.是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺分账记录信息';

-- ----------------------------
-- Records of lkt_mch_distribution_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_order_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_order_record`;
CREATE TABLE `lkt_mch_order_record` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '店铺交易数据id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `count_day` timestamp NULL DEFAULT NULL COMMENT '日期',
  `order_num` int NOT NULL DEFAULT '0' COMMENT '订单数量',
  `money` decimal(10,2) NOT NULL COMMENT '金额',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `recycle` int NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.系统回收 2用户回收 3店铺回收',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺交易数据表';

-- ----------------------------
-- Records of lkt_mch_order_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_promise
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_promise`;
CREATE TABLE `lkt_mch_promise` (
  `id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '主键',
  `orderNo` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单号',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `promise_amt` decimal(10,2) NOT NULL COMMENT '保证金金额',
  `status` int NOT NULL DEFAULT '1' COMMENT '保证金状态 1=已交 2=已退还',
  `pay_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'wallet_pay' COMMENT '支付方式',
  `is_return_pay` int NOT NULL DEFAULT '0' COMMENT '是否退还',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `update_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `paypal_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '贝宝订单号',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺保证金记录表';

-- ----------------------------
-- Records of lkt_mch_promise
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_statistics
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_statistics`;
CREATE TABLE `lkt_mch_statistics` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '店铺数据汇总id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `pending_shipment` int NOT NULL DEFAULT '0' COMMENT '待发货订单',
  `obligation` int NOT NULL DEFAULT '0' COMMENT '待付款订单',
  `refund_order` int NOT NULL DEFAULT '0' COMMENT '退款订单',
  `audit_order` int NOT NULL DEFAULT '0' COMMENT '待审核订单',
  `audit_pro` int NOT NULL DEFAULT '0' COMMENT '待审核商品',
  `ckbz_pro` int NOT NULL DEFAULT '0' COMMENT '库存不足商品',
  `djs_order` int NOT NULL DEFAULT '0' COMMENT '待结算订单',
  `dsh_order` int NOT NULL DEFAULT '0' COMMENT '待收货订单',
  `sj_pro` int NOT NULL DEFAULT '0' COMMENT '上架商品',
  `xj_pro` int NOT NULL DEFAULT '0' COMMENT '下架商品',
  `pro_class` int NOT NULL DEFAULT '0' COMMENT '商品分类',
  `pro_brand` int NOT NULL DEFAULT '0' COMMENT '商品品牌',
  `sale_pro_sku` int NOT NULL DEFAULT '0' COMMENT '销售商品sku',
  `pro_sku` int NOT NULL DEFAULT '0' COMMENT '商品sku数量',
  `customer_num` int NOT NULL DEFAULT '0' COMMENT '总客单数量',
  `attention_user_num` int NOT NULL DEFAULT '0' COMMENT '关注的客户',
  `access_user_num` int NOT NULL DEFAULT '0' COMMENT '访问的客户',
  `new_pay_user` int NOT NULL DEFAULT '0' COMMENT '新增下单客户',
  `djs_money` decimal(10,2) NOT NULL COMMENT '待结算金额',
  `ytx_money` decimal(10,2) NOT NULL COMMENT '已提现金额',
  `return_money` decimal(10,2) NOT NULL COMMENT '退款金额',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `recycle` int NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.系统回收 2用户回收 3店铺回收',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺数据汇总表';

-- ----------------------------
-- Records of lkt_mch_statistics
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_store
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_store`;
CREATE TABLE `lkt_mch_store` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int NOT NULL DEFAULT '0' COMMENT '店铺ID',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '门店名称',
  `mobile` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '联系电话',
  `business_hours` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '营业时间',
  `sheng` char(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '省',
  `shi` char(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '市',
  `xian` char(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '县',
  `address` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '详细地址',
  `add_date` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `longitude` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '经度',
  `latitude` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '纬度',
  `is_default` tinyint DEFAULT '0' COMMENT '是否默认 0.不默认 1.默认',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺门店表';

-- ----------------------------
-- Records of lkt_mch_store
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_store_account
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_store_account`;
CREATE TABLE `lkt_mch_store_account` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int NOT NULL DEFAULT '0' COMMENT '店铺ID',
  `mch_store_id` int NOT NULL COMMENT '门店id',
  `account_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '账号',
  `password` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '密码',
  `add_date` timestamp NOT NULL COMMENT '添加时间',
  `last_login` timestamp NULL DEFAULT NULL COMMENT '上次登录时间',
  `recycle` int DEFAULT '0' COMMENT '是否回收',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺门店账号表';

-- ----------------------------
-- Records of lkt_mch_store_account
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_mch_store_write
-- ----------------------------
DROP TABLE IF EXISTS `lkt_mch_store_write`;
CREATE TABLE `lkt_mch_store_write` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int NOT NULL DEFAULT '0' COMMENT '店铺ID',
  `mch_store_id` int NOT NULL COMMENT '门店id',
  `start_time` timestamp NULL DEFAULT NULL COMMENT '开始日期',
  `end_time` timestamp NULL DEFAULT NULL COMMENT '结束日期',
  `period` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '默认时间段',
  `write_off_num` int DEFAULT '0' COMMENT '可预约核销次数 0无限制',
  `off_num` text CHARACTER SET utf8 COLLATE utf8_bin COMMENT '已预约核销次数',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `recycle` int NOT NULL DEFAULT '0' COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='虚拟商品订单核销表';

-- ----------------------------
-- Records of lkt_mch_store_write
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_member_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_member_config`;
CREATE TABLE `lkt_member_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `is_open` int NOT NULL DEFAULT '0' COMMENT '会员插件开关 0.关 1.开',
  `open_config` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '开通设置',
  `birthday_open` int NOT NULL DEFAULT '0' COMMENT '会员生日特权开关 0.关 1.开',
  `points_multiple` int DEFAULT '1' COMMENT '积分倍数',
  `bonus_points_open` int NOT NULL DEFAULT '0' COMMENT '会员赠送积分开关 0.关 1.开',
  `bonus_points_config` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '会员赠送积分设置',
  `member_discount` decimal(10,2) NOT NULL COMMENT '会员打折率',
  `renew_open` int NOT NULL DEFAULT '0' COMMENT '续费提醒开关 0.关 1.开',
  `renew_day` int DEFAULT '7' COMMENT '开始续费提醒天数',
  `member_equity` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '会员权益设置',
  `add_time` timestamp NOT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='会员设置表';

-- ----------------------------
-- Records of lkt_member_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_member_pro
-- ----------------------------
DROP TABLE IF EXISTS `lkt_member_pro`;
CREATE TABLE `lkt_member_pro` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `pro_id` int NOT NULL DEFAULT '0' COMMENT '商品id',
  `recovery` int NOT NULL DEFAULT '0' COMMENT '是否回收 0.否 1是',
  `add_time` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='会员商品表';

-- ----------------------------
-- Records of lkt_member_pro
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_menu
-- ----------------------------
DROP TABLE IF EXISTS `lkt_menu`;
CREATE TABLE `lkt_menu` (
  `id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'id',
  `main_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '归类主键id(例如 门店id/店铺id/商城id)',
  `type` int NOT NULL COMMENT '1=门店id 2=店铺id 3=商城id',
  `sid` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '上级id',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '菜单名称',
  `level` int DEFAULT '1' COMMENT '菜单等级',
  `logo` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '菜单logo',
  `checked_logo` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '选中后菜单logo',
  `path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '页面所在路径文件夹 [vue-动态路由里的 path]',
  `url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '页面路径 [vue-动态路由里的 component]',
  `text` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '菜单说明',
  `is_display` int DEFAULT '0' COMMENT '是否禁用 1=是 0=否',
  `sort` int DEFAULT '0' COMMENT '排序序号',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `update_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='通用 菜单表';

