-- ----------------------------
-- Table structure for lkt_message
-- ----------------------------
DROP TABLE IF EXISTS `lkt_message`;
CREATE TABLE `lkt_message` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `SignName` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '短信签名',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '短信模板名称',
  `type` int NOT NULL DEFAULT '0' COMMENT '类型 0:验证码 1:自定义',
  `type1` int NOT NULL DEFAULT '0' COMMENT '类别 0:通用 1:申请通过 2:申请拒绝 3:订单提现 4:发货提现 5:收货提现',
  `TemplateCode` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '短信模板Code',
  `content` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '内容',
  `add_time` timestamp NOT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='短信模板列表';

-- ----------------------------
-- Records of lkt_message
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_message_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_message_config`;
CREATE TABLE `lkt_message_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `accessKeyId` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'accessKeyId',
  `accessKeySecret` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'accessKeySecret',
  `SignName` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '短信签名',
  `add_time` datetime NOT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='短信配置';

-- ----------------------------
-- Records of lkt_message_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_message_list
-- ----------------------------
DROP TABLE IF EXISTS `lkt_message_list`;
CREATE TABLE `lkt_message_list` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `type` int NOT NULL DEFAULT '0' COMMENT '类型 0:验证码 1:短信通知',
  `type1` int NOT NULL DEFAULT '0' COMMENT '类别 0:通用 1:申请通过 2:申请拒绝 3:订单提现 4:发货提现 5:收货提现',
  `Template_id` int NOT NULL DEFAULT '0' COMMENT '模板id',
  `content` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'code',
  `status` int NOT NULL DEFAULT '0' COMMENT '类型 0:商城 1:店铺',
  `admin_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '客户id/店主id',
  `add_time` datetime NOT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='短信列表(未使用  勿删)-->该表使用功能为：商城--短信配置--短信列表  ///该功能已取消但是功能代码未删除';

-- ----------------------------
-- Records of lkt_message_list
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_message_logging
-- ----------------------------
DROP TABLE IF EXISTS `lkt_message_logging`;
CREATE TABLE `lkt_message_logging` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int NOT NULL DEFAULT '0' COMMENT '店铺id',
  `type` tinyint NOT NULL DEFAULT '1' COMMENT '消息类型 1.订单(待发货) 2.订单(售后) 3.订单(提醒发货) 4.订单(订单关闭) 5.订单(新订单) 6.订单(收货) 7.商品(审核) 8.商品(下架) 9.商品(补货) 10.商品(新商品上架) 11.商品(分类) 12.商品(品牌)',
  `parameter` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '参数',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '内容',
  `is_popup` tinyint NOT NULL DEFAULT '0' COMMENT '是否弹窗 0.未弹 1.已弹',
  `read_or_not` tinyint NOT NULL DEFAULT '0' COMMENT '是否已读 0.未读 1.已读',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `to_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '前端路由地址',
  `supplier_id` int DEFAULT NULL COMMENT '供应商id',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id_idx` (`store_id`) USING BTREE,
  KEY `mch_id_idx` (`mch_id`) USING BTREE,
  KEY `is_popup_idx` (`is_popup`) USING BTREE,
  KEY `read_or_not_idx` (`read_or_not`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='店铺消息记录表';

-- ----------------------------
-- Records of lkt_message_logging
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_notice
-- ----------------------------
DROP TABLE IF EXISTS `lkt_notice`;
CREATE TABLE `lkt_notice` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '配置id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `pay_success` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '支付成功通知',
  `order_delivery` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '发货通知',
  `delivery` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单发货通知',
  `refund_res` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '退款通知',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='模板消息表';

-- ----------------------------
-- Records of lkt_notice
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_online_message
-- ----------------------------
DROP TABLE IF EXISTS `lkt_online_message`;
CREATE TABLE `lkt_online_message` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int DEFAULT NULL,
  `send_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '发送信息id',
  `receive_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '接收信息id',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '发送的内容',
  `is_mch_send` int DEFAULT '0' COMMENT '是否店铺发送 0否 1 是 店铺发送 id 为店铺id',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '发送消息时间',
  `is_read` int DEFAULT '0' COMMENT '是否已读  0 否 1 是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='在线信息表';

-- ----------------------------
-- Records of lkt_online_message
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_order
-- ----------------------------
DROP TABLE IF EXISTS `lkt_order`;
CREATE TABLE `lkt_order` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户id',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '姓名',
  `mobile` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '联系电话',
  `num` int DEFAULT NULL COMMENT '数量',
  `old_total` decimal(12,2) DEFAULT NULL COMMENT '历史总价',
  `z_price` decimal(12,2) DEFAULT NULL COMMENT '总价',
  `sNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  `sheng` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '省',
  `shi` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '市',
  `xian` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '县',
  `address` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '详细地址',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户备注',
  `pay` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '支付方式',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `pay_time` timestamp NULL DEFAULT NULL COMMENT '支付时间',
  `arrive_time` timestamp NULL DEFAULT NULL COMMENT '到货时间',
  `order_failure_time` int DEFAULT NULL COMMENT '订单当前失效时间',
  `status` tinyint DEFAULT '0' COMMENT '状态 0:未付款 1:未发货 2:待收货 5:已完成  7:订单关闭 8:待核销',
  `coupon_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '优惠券id',
  `subtraction_id` int DEFAULT NULL COMMENT '满减活动ID',
  `consumer_money` int DEFAULT '0' COMMENT '消费金',
  `coupon_activity_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '满减活动名称',
  `drawid` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '活动ID',
  `otype` char(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '订单类型',
  `ptcode` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '拼团编号',
  `pid` char(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拼团订单类型:kaituan开团 cantuan参团',
  `ptstatus` smallint DEFAULT NULL COMMENT '拼团状态:0,未付款 1,拼团中 2,拼团成功 3,拼团失败',
  `groupman` char(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拼团人数',
  `refundsNo` char(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '拼团退款单号',
  `trade_no` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '微信支付单号',
  `is_anonymous` int DEFAULT '0' COMMENT '是否匿名(0,否  1.是',
  `logistics_service` int DEFAULT NULL COMMENT '物流服务',
  `overall_evaluation` int DEFAULT NULL COMMENT '总体评价',
  `spz_price` decimal(10,2) DEFAULT NULL COMMENT '商品总价',
  `reduce_price` decimal(10,2) DEFAULT '0.00' COMMENT '查询出的满减金额',
  `coupon_price` decimal(10,2) DEFAULT '0.00' COMMENT '查询出的总优惠券金额',
  `red_packet` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '红包金额',
  `allow` int DEFAULT '0' COMMENT '积分',
  `parameter` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '参数',
  `source` tinyint NOT NULL DEFAULT '1' COMMENT '来源 1.小程序 2.app 3.支付宝小程序 4.头条小程序 5.百度小程序 6.pc端 7.H5',
  `delivery_status` int DEFAULT '0' COMMENT '提醒发货',
  `readd` int NOT NULL DEFAULT '0' COMMENT '是否已读（0，未读  1 已读）',
  `remind` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '提醒\r\n\r\n发货时间间隔',
  `offset_balance` decimal(10,2) DEFAULT NULL COMMENT '抵扣余额',
  `mch_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '店铺ID',
  `zhekou` decimal(10,2) DEFAULT NULL COMMENT '分销折扣',
  `grade_rate` decimal(10,2) DEFAULT '0.00' COMMENT '会员等级折扣',
  `vip_source` tinyint(1) DEFAULT '0' COMMENT '是否为会员订单 0：否 1：是',
  `score_deduction` decimal(15,2) DEFAULT NULL COMMENT '积分支付抵扣',
  `grade_score` int DEFAULT '0' COMMENT '会员购物积分',
  `grade_fan` decimal(12,2) DEFAULT NULL COMMENT '会员返现金额',
  `p_sNo` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '父类订单号',
  `bargain_id` int DEFAULT NULL COMMENT '砍价活动id',
  `comm_discount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '分销折扣',
  `real_sno` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '调起支付所用订单号',
  `orderId` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '官方订单号',
  `baiduId` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '百度用户ID',
  `remarks` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '订单备注',
  `self_lifting` tinyint DEFAULT '0' COMMENT '自提 0.配送 1.自提 2.商家自配 3.虚拟订单需要线下核销 4.虚拟订单无需线下核销',
  `extraction_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '提现码',
  `extraction_code_img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '提现码二维码',
  `VerifiedBy_type` tinyint(1) DEFAULT '1' COMMENT '核销人类型 1.店主核销 2.门店核销',
  `VerifiedBy` int DEFAULT '0' COMMENT '核销人ID',
  `is_put` tinyint DEFAULT '0' COMMENT '是否发放佣金 0.否 1.是',
  `old_freight` decimal(12,2) DEFAULT NULL COMMENT '历史总运费',
  `z_freight` decimal(12,2) DEFAULT NULL COMMENT '总运费',
  `manual_offer` decimal(12,2) DEFAULT NULL COMMENT '代客下单手动优惠金额',
  `preferential_amount` decimal(12,2) DEFAULT '0.00' COMMENT '平台优惠券金额',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.系统回收 2用户回收 3店铺回收',
  `single_store` int NOT NULL DEFAULT '0' COMMENT '下单门店/自提门店',
  `pick_up_store` tinyint NOT NULL DEFAULT '0' COMMENT '取货门店',
  `store_write_time` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '虚拟商品预约时间',
  `platform_activities_id` int DEFAULT NULL COMMENT '平台活动管理ID',
  `commission_type` tinyint(1) DEFAULT '0' COMMENT '分销订单结算标识0未结算1已结算',
  `settlement_status` tinyint(1) DEFAULT '0' COMMENT '结算状态',
  `operation_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '下单类型1用户下单2店铺下单3平台下单',
  `is_lssued` int DEFAULT '0' COMMENT '店铺是否操作代发 0.否 1.是',
  `user_recycle` int DEFAULT '1' COMMENT '用户删除 1.显示 2.删除',
  `mch_recycle` int DEFAULT '1' COMMENT '商户删除 1.显示 2.删除',
  `store_recycle` int DEFAULT '1' COMMENT '商城删除 1.显示 2.删除',
  `transaction_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '微信返回支付单号唯一标识',
  `wx_order_status` int DEFAULT NULL COMMENT '微信小程序订单状态枚举：(1) 待发货；(2) 已发货；(3) 确认收货；(4) 交易完成；(5) 已退款。',
  `dividend_status` int DEFAULT '0' COMMENT '分账状态 0.不分账 1.分账',
  `cancel_method` int DEFAULT '0' COMMENT '订单取消方式 0 定时任务取消订单  1 手动点击取消订单',
  `paypal_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '贝宝支付订单id',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `user_id` (`user_id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `sNo` (`sNo`(191)) USING BTREE,
  KEY `subtraction_id` (`subtraction_id`) USING BTREE,
  KEY `store_id_2` (`store_id`) USING BTREE,
  KEY `user_id_2` (`user_id`) USING BTREE,
  KEY `sNo_2` (`sNo`(191)) USING BTREE,
  KEY `status` (`status`) USING BTREE,
  KEY `mch_id` (`mch_id`(191)) USING BTREE,
  KEY `otype` (`otype`) USING BTREE,
  KEY `recycle` (`recycle`) USING BTREE,
  KEY `add_time` (`add_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='订单列表';

-- ----------------------------
-- Records of lkt_order
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_order_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_order_config`;
CREATE TABLE `lkt_order_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `days` int DEFAULT NULL COMMENT '承若天数',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '规则内容',
  `back` int DEFAULT '2' COMMENT '退货时间',
  `order_failure` int DEFAULT NULL COMMENT '订单失效',
  `order_after` int NOT NULL DEFAULT '7' COMMENT '订单售后时间',
  `company` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '天' COMMENT '单位',
  `order_overdue` int DEFAULT '2' COMMENT '订单过期删除时间',
  `unit` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '天' COMMENT '单位',
  `modify_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `auto_the_goods` int DEFAULT '7' COMMENT '自动收货时间',
  `order_ship` int NOT NULL DEFAULT '0' COMMENT '发货时限',
  `remind` int DEFAULT '1' COMMENT '提醒限制',
  `accesscode` char(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '顾客编码',
  `checkword` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '校验码',
  `custid` char(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '月结卡号',
  `package_settings` tinyint DEFAULT '0' COMMENT '包邮设置 0.未开启 1.开启',
  `same_piece` int DEFAULT '0' COMMENT '同件',
  `same_order` int DEFAULT '0' COMMENT '同单',
  `auto_good_comment_day` smallint NOT NULL DEFAULT '0' COMMENT '自动评价设置几后自动好评',
  `auto_good_comment_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '自动评价内容',
  `proportion` decimal(10,0) DEFAULT NULL COMMENT '积分比例(购物赠送积分=购物交易金额*赠送比例)',
  `give_status` int DEFAULT '0' COMMENT '发放状态(0=收货后 1=付款后)',
  `ams_time` int DEFAULT '0' COMMENT '收货后多少天返回积分，至 x 失效',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='订单设置';

-- ----------------------------
-- Records of lkt_order_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_order_data
-- ----------------------------
DROP TABLE IF EXISTS `lkt_order_data`;
CREATE TABLE `lkt_order_data` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `trade_no` char(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '微信订单号',
  `order_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单类型',
  `data` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `addtime` timestamp NOT NULL COMMENT '创建时间',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '支付状态 0未支付 1已支付',
  `pay_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'wallet_pay' COMMENT '支付方式',
  `source` int NOT NULL DEFAULT '1' COMMENT '来源',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='订单临时信息表';

-- ----------------------------
-- Records of lkt_order_data
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_order_details
-- ----------------------------
DROP TABLE IF EXISTS `lkt_order_details`;
CREATE TABLE `lkt_order_details` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int DEFAULT '0' COMMENT '商城id',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户id',
  `p_id` int NOT NULL DEFAULT '0' COMMENT '产品id(插件则是插件商品id 拼团存的是开团id)',
  `p_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '产品名称',
  `p_price` decimal(12,2) DEFAULT NULL COMMENT '产品价格',
  `num` int DEFAULT NULL COMMENT '数量',
  `actual_total` decimal(15,2) DEFAULT NULL COMMENT '实际支付金额',
  `score_deduction` int DEFAULT NULL COMMENT '积分支付抵扣',
  `unit` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '单位',
  `r_sNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  `is_addp` tinyint(1) DEFAULT NULL COMMENT '是否加购商品 0：否 1：是',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `deliver_time` timestamp NULL DEFAULT NULL COMMENT '发货时间',
  `arrive_time` timestamp NULL DEFAULT NULL COMMENT '到货时间',
  `r_status` tinyint DEFAULT '0' COMMENT '状态 0:未付款 1:未发货 2:待收货 5:已完成  7:订单关闭 8:待核销',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '退货原因',
  `reason` char(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'app退款原因',
  `re_type` tinyint DEFAULT '0' COMMENT '退款类型 1:退货退款  2:退款 3:售后',
  `re_apply_money` float(12,2) DEFAULT NULL COMMENT '用户申请退款金额',
  `re_money` float(12,2) DEFAULT NULL COMMENT '退款金额',
  `real_money` decimal(12,2) DEFAULT NULL COMMENT '实际退款金额',
  `re_time` timestamp NULL DEFAULT NULL COMMENT '申请退款时间',
  `re_photo` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '上传凭证',
  `audit_time` timestamp NULL DEFAULT NULL COMMENT '审核时间',
  `r_content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '拒绝原因',
  `r_type` tinyint DEFAULT '100' COMMENT '类型 100:不在退货退款状态0:审核中 1:同意并让用户寄回 2:拒绝(退货退款) 3:用户已快递 4:收到寄回商品,同意并退款 5：拒绝并退回商品 8:拒绝(退款) 9:同意并退款 10:拒绝(售后)11:同意并且寄回商品 12售后结束',
  `express_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '快递公司id ,号分隔',
  `courier_num` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '快递单号 ,号分隔',
  `express_type` tinyint DEFAULT '1' COMMENT '发货类型 1.手动发货 2.自动发货',
  `freight` decimal(12,2) DEFAULT NULL COMMENT '运费',
  `size` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '配置名称',
  `sid` char(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '规格属性id',
  `invoice` tinyint DEFAULT '0' COMMENT '发货单打印 0.否 1.是',
  `express` tinyint DEFAULT '0' COMMENT '快递单打印 0.否 1.是',
  `exchange_num` int DEFAULT '0' COMMENT '换货次数',
  `coupon_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '优惠券id',
  `manual_offer` decimal(12,2) DEFAULT NULL COMMENT '代课下单手动优惠金额',
  `after_discount` decimal(12,2) DEFAULT NULL COMMENT '优惠后的金额',
  `mch_id` int DEFAULT NULL COMMENT '店铺ID',
  `settlement_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '订单结算标识 0未结算 1已结算',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.回收',
  `supplier_settlement` decimal(12,2) DEFAULT NULL COMMENT '总供货价',
  `user_recycle` int DEFAULT '1' COMMENT '用户删除 1.显示 2.删除',
  `mch_recycle` int DEFAULT '1' COMMENT '商户删除 1.显示 2.删除',
  `store_recycle` int DEFAULT '1' COMMENT '商城删除 1.显示 2.删除',
  `deliver_num` int DEFAULT '0' COMMENT '发货数量',
  `third_party_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '第三方订单号',
  `third_party_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '第三方订单信息',
  `living_room_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '直播间id',
  `anchor_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '主播id',
  `commission` decimal(10,2) DEFAULT NULL COMMENT '佣金',
  `write_off_num` int DEFAULT NULL COMMENT '虚拟商品待核销次数',
  `after_write_off_num` int DEFAULT NULL COMMENT '虚拟商品已核销次数',
  `mch_store_write_id` int DEFAULT NULL COMMENT '预约门店id',
  `write_time` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '虚拟商品预约时间',
  `write_time_id` int DEFAULT NULL COMMENT '预约时段id',
  `platform_coupon_price` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '平台优惠券优惠金额',
  `store_coupon_price` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '店铺优惠券优惠金额',
  `store_self_delivery` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '商家自配信息id',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `user_id` (`user_id`) USING BTREE,
  KEY `r_sNo` (`r_sNo`(191)) USING BTREE,
  KEY `sid` (`sid`) USING BTREE,
  KEY `store_id_2` (`store_id`) USING BTREE,
  KEY `mch_id` (`mch_id`) USING BTREE,
  KEY `recycle` (`recycle`) USING BTREE,
  KEY `p_id` (`p_id`) USING BTREE,
  KEY `r_status` (`r_status`) USING BTREE,
  KEY `re_type` (`re_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='订单详情列表';

-- ----------------------------
-- Records of lkt_order_details
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_order_report
-- ----------------------------
DROP TABLE IF EXISTS `lkt_order_report`;
CREATE TABLE `lkt_order_report` (
  `type` tinyint NOT NULL COMMENT '统计指标 5 用户报表 8 西凉州',
  `num` bigint DEFAULT '0' COMMENT '数量',
  `data` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '统计数据',
  `store_id` int DEFAULT NULL COMMENT '商城id'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='订单数据统计表';

-- ----------------------------
-- Records of lkt_order_report
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_payment
-- ----------------------------
DROP TABLE IF EXISTS `lkt_payment`;
CREATE TABLE `lkt_payment` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '支付名称',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1:线上、2:线下',
  `class_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '支付类名称',
  `description` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '描述',
  `logo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '支付方式logo图片路径',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 0启用 1禁用',
  `sort` smallint NOT NULL DEFAULT '99' COMMENT '排序',
  `note` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '支付说明',
  `poundage` decimal(15,2) NOT NULL COMMENT '手续费',
  `poundage_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '手续费方式 1百分比 2固定值',
  `client_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1:PC端 2:移动端 3:通用',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='支付方式表';

