-- Table structure for lkt_payment_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_payment_config`;
CREATE TABLE `lkt_payment_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `pid` int NOT NULL COMMENT '支付方式id',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否显示 0否 1是',
  `config_data` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '配置参数,json数据对象',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='支付方式参数表';

