-- ----------------------------
-- Table structure for lkt_pc_mall_bottom
-- ----------------------------
DROP TABLE IF EXISTS `lkt_pc_mall_bottom`;
CREATE TABLE `lkt_pc_mall_bottom` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL COMMENT '商城id',
  `image` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '图片地址',
  `title` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '标题',
  `subheading` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '副标题',
  `sort` int NOT NULL DEFAULT '0' COMMENT '排序号',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `update_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='PC商城底部栏图片配置';

-- ----------------------------
-- Records of lkt_pc_mall_bottom
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_pc_mall_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_pc_mall_config`;
CREATE TABLE `lkt_pc_mall_config` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL COMMENT '商城id',
  `type` int DEFAULT NULL COMMENT '配置类型 1浏览器标签 2 登录页配置 3 首页配置',
  `value` text CHARACTER SET utf8 COLLATE utf8_general_ci COMMENT '配置值',
  `add_date` datetime DEFAULT NULL COMMENT '添加时间',
  `update_date` datetime DEFAULT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='PC商城页面显示配置';

-- ----------------------------
-- Records of lkt_pc_mall_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_platform_activities
-- ----------------------------
DROP TABLE IF EXISTS `lkt_platform_activities`;
CREATE TABLE `lkt_platform_activities` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int NOT NULL COMMENT '商品id',
  `image` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '封面图片',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动名称',
  `type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动类型 如 pt:拼团 ms:秒杀',
  `status` tinyint(1) NOT NULL COMMENT '活动状态 （1未开始 2进行中 3结束）',
  `default_num` int NOT NULL DEFAULT '0' COMMENT '默认数量（秒杀）',
  `buy_time` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '秒杀时段（秒杀）',
  `group_man` int NOT NULL DEFAULT '0' COMMENT '拼团人数（拼团）',
  `group_can` int NOT NULL DEFAULT '0' COMMENT '参团折扣（拼团）',
  `group_kai` int NOT NULL DEFAULT '0' COMMENT '开团折扣（拼团）',
  `group_time` int NOT NULL DEFAULT '0' COMMENT '拼团时间（拼团）',
  `group_kai_num` int NOT NULL DEFAULT '0' COMMENT '开团数量限制（拼团）',
  `group_can_num` int NOT NULL DEFAULT '0' COMMENT '参团数量限制（拼团）',
  `group_can_again` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启参团重复 （1开启 0不开启）（拼团）',
  `free_freight` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否免邮(1 是 0 否)',
  `starttime` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '开始时间',
  `endtime` timestamp NOT NULL COMMENT '结束时间',
  `join_starttime` timestamp NOT NULL COMMENT '报名开始时间',
  `join_endtime` timestamp NOT NULL COMMENT '报名结束时间',
  `isdelete` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除(1 是 0 否)',
  `addtime` timestamp NOT NULL COMMENT '添加日期',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='平台活动表';

-- ----------------------------
-- Records of lkt_platform_activities
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_platform_activities_del
-- ----------------------------
DROP TABLE IF EXISTS `lkt_platform_activities_del`;
CREATE TABLE `lkt_platform_activities_del` (
  `id` int NOT NULL AUTO_INCREMENT,
  `platform_activities_id` int DEFAULT NULL COMMENT '平台活动ID',
  `mch_id` int DEFAULT NULL COMMENT '商户ID',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商户删除平台管理活动表';

-- ----------------------------
-- Records of lkt_platform_activities_del
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_plug_ins
-- ----------------------------
DROP TABLE IF EXISTS `lkt_plug_ins`;
CREATE TABLE `lkt_plug_ins` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `name` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '插件名称',
  `Identification` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '标识',
  `sort` int DEFAULT NULL COMMENT '排序',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 0：未启用 1：启用',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='插件表';

-- ----------------------------
-- Records of lkt_plug_ins
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_plugins
-- ----------------------------
DROP TABLE IF EXISTS `lkt_plugins`;
CREATE TABLE `lkt_plugins` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `plugin_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '插件名称',
  `plugin_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '插件编码',
  `plugin_img` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '插件图标',
  `optime` timestamp NULL DEFAULT NULL COMMENT '安装时间',
  `status` int DEFAULT '1' COMMENT '安装状态0失败1成功',
  `flag` int NOT NULL DEFAULT '0' COMMENT '卸载状态0未卸载1已卸载',
  `opuser` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '操作人用户名',
  `jump_address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '插件跳转地址',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '插件表新增插件描述字段',
  `menu_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '插件对应通用菜单表id(用于控制pc店铺插件菜单是否显示)',
  `is_mch_plugin` int NOT NULL DEFAULT '1' COMMENT '插件是否支持pc店铺 1支持 2不支持',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1386 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='插件信息';

