-- ----------------------------
-- Table structure for lkt_pre_sell_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_pre_sell_config`;
CREATE TABLE `lkt_pre_sell_config` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键自增',
  `store_id` int NOT NULL COMMENT '店铺id',
  `is_open` tinyint NOT NULL DEFAULT '0' COMMENT '是否开启 1 是 0 否',
  `deposit_desc` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订金预售说明',
  `balance_desc` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订货预售说明',
  `order_failure` int NOT NULL DEFAULT '0' COMMENT '订单失效 (单位 秒)',
  `order_after` int NOT NULL DEFAULT '604800' COMMENT '订单售后时间 (单位秒)',
  `auto_the_goods` int NOT NULL DEFAULT '7' COMMENT '自动收货时间（单位秒）',
  `deliver_remind` int NOT NULL DEFAULT '3600' COMMENT '提醒发货限制 间隔(单位秒)',
  `package_settings` tinyint NOT NULL DEFAULT '0' COMMENT '多件包邮设置 0.未开启 1.开启',
  `same_piece` int NOT NULL DEFAULT '0' COMMENT '同件',
  `same_order` int NOT NULL DEFAULT '0' COMMENT '同单',
  `auto_good_comment_day` int NOT NULL DEFAULT '0' COMMENT '自动评价设置几后自动好评',
  `auto_good_comment_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '自动评价内容',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='预售配置信息';

-- ----------------------------
-- Records of lkt_pre_sell_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_pre_sell_goods
-- ----------------------------
DROP TABLE IF EXISTS `lkt_pre_sell_goods`;
CREATE TABLE `lkt_pre_sell_goods` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '唯一标识',
  `product_id` int NOT NULL COMMENT '商品id',
  `product_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '商品名称',
  `sell_type` int NOT NULL DEFAULT '1' COMMENT '预售类型   1.订金模式   2.订货模式',
  `deposit` decimal(20,2) DEFAULT NULL COMMENT '订金金额',
  `pay_type` int DEFAULT NULL COMMENT '订金支付类型',
  `deposit_start_time` datetime DEFAULT NULL COMMENT '订金支付开始时间',
  `deposit_end_time` datetime DEFAULT NULL COMMENT '订金支付结束时间',
  `balance_pay_time` datetime DEFAULT NULL COMMENT '尾款支付日期',
  `sell_num` int DEFAULT NULL COMMENT '预售数量',
  `surplus_num` int DEFAULT NULL COMMENT '剩余数量',
  `end_day` int DEFAULT '1' COMMENT '截止天数',
  `deadline` timestamp NULL DEFAULT NULL COMMENT '截止时间',
  `delivery_time` int NOT NULL COMMENT '发货时间(天)',
  `is_on_shelf` int NOT NULL DEFAULT '0' COMMENT '是否上架过',
  `is_display` int NOT NULL DEFAULT '1' COMMENT '是否显示 0.否  1.是',
  `is_delete` int NOT NULL DEFAULT '0' COMMENT '是否删除  0.否  1.是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='预售商品表';

-- ----------------------------
-- Records of lkt_pre_sell_goods
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_pre_sell_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_pre_sell_record`;
CREATE TABLE `lkt_pre_sell_record` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int NOT NULL COMMENT '商城id',
  `user_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户id',
  `product_id` int NOT NULL COMMENT '商品id',
  `attr_id` int NOT NULL COMMENT '规格id',
  `price` decimal(11,2) NOT NULL COMMENT '当前付款金额',
  `deposit` decimal(11,2) DEFAULT NULL COMMENT '应付订金金额',
  `balance` decimal(11,2) DEFAULT NULL COMMENT '应付尾款金额',
  `num` int NOT NULL COMMENT '数量',
  `sNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '预售订单号',
  `pay_type` int DEFAULT NULL COMMENT '支付类型 0.定金 1.尾款',
  `is_pay` int DEFAULT '0' COMMENT '是否支付 0.未支付 1.已支付',
  `is_refund` int DEFAULT '0' COMMENT '是否退款成功  0.否  1.是',
  `is_delete` int NOT NULL DEFAULT '0' COMMENT '是否删除 1是 0否',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '订金支付时间',
  `pay_balance_time` timestamp NULL DEFAULT NULL COMMENT '尾款支付时间',
  `order_info` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '订单信息',
  `order_details_info` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '订单详情信息',
  `real_sno` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '支付订单号',
  `pay` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '支付方式',
  `paypal_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '贝宝订单id',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='预售记录表';

-- ----------------------------
-- Records of lkt_pre_sell_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_print_setup
-- ----------------------------
DROP TABLE IF EXISTS `lkt_print_setup`;
CREATE TABLE `lkt_print_setup` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int NOT NULL COMMENT '商城id',
  `mch_id` int DEFAULT NULL COMMENT '店铺id',
  `supplier_id` int DEFAULT NULL COMMENT '供应商id',
  `print_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '打印名称',
  `print_url` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '打印网址',
  `sheng` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '省',
  `shi` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '市',
  `xian` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '县',
  `address` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '详细地址',
  `phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '联系电话',
  `add_time` datetime DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `mch_id` (`mch_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='订单打印配置';

-- ----------------------------
-- Records of lkt_print_setup
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_pro_label
-- ----------------------------
DROP TABLE IF EXISTS `lkt_pro_label`;
CREATE TABLE `lkt_pro_label` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城ID',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '商品标签',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `color` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '1' COMMENT '颜色 编码',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商品标签表';

-- ----------------------------
-- Records of lkt_pro_label
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_product_class
-- ----------------------------
DROP TABLE IF EXISTS `lkt_product_class`;
CREATE TABLE `lkt_product_class` (
  `cid` int unsigned NOT NULL AUTO_INCREMENT COMMENT '分类id',
  `sid` int NOT NULL COMMENT '上级id',
  `pname` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分类名称',
  `english_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '英文名称',
  `img` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '分类图片',
  `bg` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '小图标',
  `level` int NOT NULL COMMENT '级别',
  `sort` int DEFAULT '100' COMMENT '排序',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `add_date` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `recycle` tinyint DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  `is_display` tinyint DEFAULT '0' COMMENT '是否显示 0.不显示 1.显示',
  `is_default` int DEFAULT '0' COMMENT '是否默认分类',
  `mch_id` int DEFAULT NULL COMMENT '店铺id',
  `examine` int DEFAULT NULL COMMENT '审核状态 0.待审核 1.审核通过 2.不通过',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '审核备注',
  `supplier_id` int DEFAULT NULL COMMENT '供应商id',
  PRIMARY KEY (`cid`) USING BTREE,
  KEY `sid` (`sid`) USING BTREE,
  KEY `pname` (`pname`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `recycle` (`recycle`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商品分类';

-- ----------------------------
-- Records of lkt_product_class
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_product_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_product_config`;
CREATE TABLE `lkt_product_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '配置',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `is_open` tinyint DEFAULT '0' COMMENT '是否显示下架商品 0.不显示  1.显示',
  `is_display_sell_put` tinyint NOT NULL DEFAULT '0' COMMENT '是否显示已售罄商品 0.不显示  1.显示',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='产品配置表';

-- ----------------------------
-- Records of lkt_product_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_product_img
-- ----------------------------
DROP TABLE IF EXISTS `lkt_product_img`;
CREATE TABLE `lkt_product_img` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '图片id',
  `product_url` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '产品图片',
  `product_id` int NOT NULL COMMENT '所属产品id',
  `seller_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户id',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `product_id` (`product_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='图片表';

-- ----------------------------
-- Records of lkt_product_img
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_product_list
-- ----------------------------
DROP TABLE IF EXISTS `lkt_product_list`;
CREATE TABLE `lkt_product_list` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '商品id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `product_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '商品编号',
  `commodity_type` tinyint DEFAULT '0' COMMENT '商品类型 0.实物商品 1.虚拟商品',
  `product_title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '商品名字',
  `subtitle` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '副标题',
  `label` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '商品标签',
  `scan` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '条形码',
  `product_class` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '产品类别',
  `imgurl` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '产品图片',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '产品内容',
  `richList` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '前端店铺商品详情插件',
  `sort` int DEFAULT NULL COMMENT '排序',
  `mch_sort` int NOT NULL DEFAULT '1' COMMENT '店铺排序值',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `upper_shelf_time` timestamp NULL DEFAULT NULL COMMENT '上架时间',
  `volume` int NOT NULL DEFAULT '0' COMMENT '销量',
  `initial` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '初始值',
  `s_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '产品值属性 1：新品,2：热销，3：推荐(字典值 商品标签)',
  `num` int NOT NULL DEFAULT '0' COMMENT '数量',
  `min_inventory` int NOT NULL DEFAULT '10' COMMENT '库存预警',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态 1:待上架 2:上架 3:下架 4:违规下架 5:断供\r\n\r\n',
  `brand_id` int NOT NULL DEFAULT '0' COMMENT '品牌ID',
  `is_distribution` int NOT NULL DEFAULT '0' COMMENT '是否为分销商品',
  `is_default_ratio` int NOT NULL DEFAULT '0' COMMENT '是否默认比例',
  `keyword` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '关键词',
  `weight` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '重量',
  `weight_unit` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '重量单位',
  `distributor_id` int DEFAULT '0' COMMENT '分销等级id 购买就升级',
  `freight` varchar(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '运费',
  `is_zhekou` int DEFAULT '0' COMMENT '是否开启会员',
  `separate_distribution` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '单独分销',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.显示 1.回收 2:草稿状态',
  `gongyingshang` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '供应商',
  `is_hexiao` tinyint DEFAULT '0' COMMENT '是否支持线下核销:0--不支持　1--支持',
  `hxaddress` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '核销地址',
  `active` char(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '1' COMMENT '支持活动:1--正价商品 2--支持拼团 3--支持砍价 4--支持竞拍 5--会员特惠',
  `mch_id` int DEFAULT '0' COMMENT '商户ID',
  `mch_status` tinyint NOT NULL DEFAULT '1' COMMENT '审核状态：1.待审核，2.审核通过，3.审核不通过，4.暂不审核',
  `refuse_reasons` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '拒绝原因',
  `search_num` int NOT NULL DEFAULT '0' COMMENT '搜索次数',
  `show_adr` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '1' COMMENT '展示位置:1.\n首页 2.购物车 3.分类 4.我的-推荐',
  `publisher` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '发布人',
  `is_zixuan` tinyint DEFAULT '1' COMMENT '是否自选 0.自选 1.不是自选',
  `commodity_str` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '商品ID字符串',
  `source` tinyint DEFAULT '2' COMMENT '商品形式 1.邮寄 2.自提',
  `comment_num` int DEFAULT '0' COMMENT '评论数',
  `cover_map` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '封面图',
  `class_sort` int DEFAULT '0' COMMENT '分类排序',
  `display_position_sort` int DEFAULT '0' COMMENT '显示位置排序',
  `is_presell` int DEFAULT '0' COMMENT '是否为预售商品 0.否  1.是',
  `supplier_superior` int DEFAULT NULL COMMENT '供应商商品上级id',
  `lower_remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '违规下架原因',
  `outage_time` timestamp NULL DEFAULT NULL COMMENT '断供时间',
  `pro_param` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '商品参数',
  `pro_introduce` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '商品介绍',
  `examine_time` timestamp NULL DEFAULT NULL COMMENT '审核时间',
  `violation_time` timestamp NULL DEFAULT NULL COMMENT '违规下架时间',
  `receiving_form` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '1' COMMENT '收货形式 1.邮寄 2.自提',
  `zixuan_id` int DEFAULT NULL COMMENT '自选id',
  `video` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '视频文件',
  `pro_video` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '商品视频',
  `real_volume` int NOT NULL DEFAULT '0' COMMENT '真实销量',
  `lower_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '违规下架原因',
  `write_off_settings` int DEFAULT NULL COMMENT '核销设置 1.线下核销 2.无需核销',
  `write_off_mch_ids` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '核销门店id  0全部门店,  1,2,3使用逗号分割',
  `is_appointment` int DEFAULT '1' COMMENT '预约时间设置 1.无需预约下单 2.需要预约下单',
  `supplier_status` int DEFAULT NULL COMMENT '供应商商品状态 用于在供应商端展示 0断供 1上架',
  `is_zc` int DEFAULT '0',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `product_title` (`product_title`) USING BTREE,
  KEY `status` (`status`) USING BTREE,
  KEY `recycle` (`recycle`) USING BTREE,
  KEY `brand_id` (`brand_id`) USING BTREE,
  KEY `mch_id` (`mch_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商品表';

-- ----------------------------
-- Records of lkt_product_list
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_product_number
-- ----------------------------
DROP TABLE IF EXISTS `lkt_product_number`;
CREATE TABLE `lkt_product_number` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '店铺id',
  `operation` varchar(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '操作人账号',
  `product_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '商品编号',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：1.使用 2.撤销',
  `addtime` timestamp NULL DEFAULT NULL COMMENT '时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商品编号表';

-- ----------------------------
-- Records of lkt_product_number
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_promise_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_promise_record`;
CREATE TABLE `lkt_promise_record` (
  `id` int NOT NULL AUTO_INCREMENT,
  `store_id` int NOT NULL COMMENT '商城ID',
  `mch_id` int NOT NULL COMMENT '店铺ID',
  `money` decimal(10,2) NOT NULL COMMENT '保证金金额',
  `type` int NOT NULL COMMENT '记录类型 1:缴纳，2:退还',
  `status` varchar(2) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '审核状态 0=审核中 1=通过 2=拒绝',
  `add_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '添加时间',
  `remarks` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '备注',
  `promise_sh_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '保证金审核id',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='保证金审核记录表';

-- ----------------------------
-- Records of lkt_promise_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_promise_sh
-- ----------------------------
DROP TABLE IF EXISTS `lkt_promise_sh`;
CREATE TABLE `lkt_promise_sh` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `promise_amt` decimal(10,2) NOT NULL COMMENT '保证金金额',
  `status` int NOT NULL DEFAULT '1' COMMENT '保证金审核状态 1=通过 2=拒绝 3=审核中',
  `pay_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'wallet_pay' COMMENT '支付方式',
  `is_pass` int NOT NULL DEFAULT '0' COMMENT '是否通过 1=通过 2=不通过 3=审核中',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `refused_why` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '拒绝原因',
  `refused_date` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '拒绝时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='保证金审核';

-- ----------------------------
-- Records of lkt_promise_sh
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_record`;
CREATE TABLE `lkt_record` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户id',
  `money` decimal(12,2) NOT NULL COMMENT '操作金额',
  `oldmoney` decimal(12,2) NOT NULL COMMENT '原有金额',
  `add_date` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `event` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '事件',
  `type` tinyint NOT NULL DEFAULT '0' COMMENT '类型 0:登录/退出 1:充值 2:申请提现 3:分享 4:余额消费 5:退款 6:红包提现 7:佣金 8:管理佣金 9:待定 10:消费金 11:系统扣款   12:给好友转余额 13:转入余额 14:系统充值 15:系统充积分 16:系统充消费金 17:系统扣积分 18:系统扣消费金 19:消费金解封 20:抽奖中奖 21:  提现成功 22:提现失败 23.取消订单  24分享获取红包 26 交竞拍押金 27 退竞拍押金 28 售后（仅退款） 29 售后（退货退款）30 会员返现\n42:主播佣金',
  `is_mch` int DEFAULT '0' COMMENT '是否是店铺提现 0.不是店铺提现 1.是店铺提现',
  `main_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '外键id',
  `details_id` int DEFAULT NULL COMMENT '记录详情id',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `lkt_record_user_id` (`user_id`(191)) USING BTREE,
  KEY `lkt_record_type` (`type`) USING BTREE,
  KEY `lkt_record_store_id` (`store_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='操作记录表';

-- ----------------------------
-- Records of lkt_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_record_details
-- ----------------------------
DROP TABLE IF EXISTS `lkt_record_details`;
CREATE TABLE `lkt_record_details` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `money` decimal(12,2) NOT NULL COMMENT '操作金额',
  `user_money` decimal(12,2) NOT NULL COMMENT '账户余额',
  `type` tinyint DEFAULT NULL COMMENT '账单类型 1 余额充值(用户)  2余额充值(平台)  3活动佣金  4订单退款 5店铺保证金提取 6 平台扣款  7 订单支付  8 参与活动  9充值会员  10 店铺保证金支付  11余额提现  12活动退款',
  `money_type` int NOT NULL COMMENT '1 收入类型  2支出类型',
  `money_type_name` tinyint DEFAULT NULL COMMENT '收入/支出 名称   1用户充值 2平台充值 3 拼团活动开团佣金 4普通订单 5竞拍活动 6店铺保证金 7余额扣款 8预售定金缴纳  9会员开通 10 普通订单(代客下单) 11拼团订单 12竟拍订单 13预售订单 14分稍订单  15秒杀订单 16积分兑换订单 17限时折扣订单 18竞拍保证金缴纳 19虚拟订单',
  `record_time` datetime DEFAULT NULL COMMENT '到账时间/提现时间/支出时间',
  `record_notes` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '备注',
  `type_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '充值方式/退款类型/活动类型',
  `s_no` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  `title_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '商品名字/活动名称',
  `activity_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '活动编号',
  `mch_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '店铺名称',
  `withdrawal_fees` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '提现手续费',
  `withdrawal_method` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT NULL COMMENT '提现方式',
  `add_time` datetime DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='操作记录详情';

-- ----------------------------
-- Records of lkt_record_details
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_reply_comments
-- ----------------------------
DROP TABLE IF EXISTS `lkt_reply_comments`;
CREATE TABLE `lkt_reply_comments` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `cid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '评论ID',
  `uid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户id',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '评价内容',
  `add_time` timestamp NOT NULL ON UPDATE CURRENT_TIMESTAMP,
  `to_uid` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '发送对象userid',
  `sid` int DEFAULT NULL COMMENT '回复的上级id',
  `type` int DEFAULT '0' COMMENT '是否是商家回复 0=用户评论 1=商家评论',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='回复评论表';

-- ----------------------------
-- Records of lkt_reply_comments
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_return_goods
-- ----------------------------
DROP TABLE IF EXISTS `lkt_return_goods`;
CREATE TABLE `lkt_return_goods` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '收货人',
  `tel` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '联系方式',
  `express` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '快递名称',
  `express_num` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '快递单号',
  `uid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '用户ID',
  `oid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '订单id',
  `add_data` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '填写时间',
  `user_id` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户id',
  `re_id` int NOT NULL DEFAULT '0' COMMENT '售后订单ID',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='用户退货表';

-- ----------------------------
-- Records of lkt_return_goods
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_return_order
-- ----------------------------
DROP TABLE IF EXISTS `lkt_return_order`;
CREATE TABLE `lkt_return_order` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `store_id` int NOT NULL COMMENT '商城ID',
  `user_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `sNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单号',
  `p_id` int NOT NULL COMMENT '订单详情ID',
  `re_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '退款类型 1:退货退款  2:退款 3:换货',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '售后原因',
  `re_apply_money` float(12,2) NOT NULL DEFAULT '0.00' COMMENT '用户申请退款金额',
  `re_money` float(12,2) NOT NULL DEFAULT '0.00' COMMENT '退款金额',
  `real_money` float(12,2) NOT NULL DEFAULT '0.00' COMMENT '实际退款金额',
  `re_time` timestamp NOT NULL COMMENT '申请售后时间',
  `re_photo` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '上传凭证',
  `audit_time` timestamp NULL DEFAULT NULL COMMENT '审核时间',
  `r_content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '拒绝原因',
  `r_type` tinyint(1) NOT NULL DEFAULT '100' COMMENT '类型 100:不在退货退款状态0:审核中 1:同意并让用户寄回 2:拒绝(退货退款) 3:用户已快递 4:收到寄回商品,同意并退款 5：拒绝并退回商品 8:拒绝(退款) 9:同意并退款 10:拒绝(售后)11:同意并且寄回商品 12售后结束 13最终状态-人工审核成功  14 人工审核失败(暂时没有这种状态) 15 订单未发货-系统自动急速退款 16 收到回寄商品,确定不影响二次销售',
  `sid` int NOT NULL COMMENT '商品属性id',
  `pid` int NOT NULL COMMENT '商品ID',
  `re_id` int NOT NULL COMMENT '售后ID',
  `is_agree` int DEFAULT '0' COMMENT '店铺是否同意 0.否 1.是',
  `r_write_off_num` int DEFAULT NULL COMMENT '虚拟商品退款核销次数',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='售后订单表';

-- ----------------------------
-- Records of lkt_return_order
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_return_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_return_record`;
CREATE TABLE `lkt_return_record` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户userid',
  `store_id` int NOT NULL COMMENT '店铺id',
  `re_type` tinyint(1) NOT NULL COMMENT '售后类型：1仅退款 2退货退款 3换货',
  `r_type` int NOT NULL COMMENT '售后状态',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '拒绝原因',
  `sNo` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '售后订单号',
  `money` decimal(10,2) NOT NULL COMMENT '售后金额',
  `real_money` decimal(10,2) DEFAULT NULL COMMENT '实际退款金额',
  `re_photo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '上传凭证',
  `product_id` int NOT NULL COMMENT '商品id',
  `attr_id` int NOT NULL COMMENT '属性id',
  `express_id` int DEFAULT NULL COMMENT '快递公司id',
  `courier_num` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '快递单号',
  `re_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '添加日期',
  `explain` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '备注',
  `p_id` int NOT NULL COMMENT '上级详情订单id',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='售后记录表';

-- ----------------------------
-- Records of lkt_return_record
-- ----------------------------
BEGIN;
COMMIT;

