-- ----------------------------
-- Table structure for lkt_seconds_activity
-- ----------------------------
DROP TABLE IF EXISTS `lkt_seconds_activity`;
CREATE TABLE `lkt_seconds_activity` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id自增',
  `store_id` int NOT NULL COMMENT '店铺id',
  `goodsId` int NOT NULL COMMENT '商品id',
  `label_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '标签id',
  `attr_id` int NOT NULL COMMENT '规格id',
  `seconds_price` decimal(11,2) NOT NULL COMMENT '秒杀价格',
  `price_type` int NOT NULL DEFAULT '0' COMMENT '秒杀价格单位 0=百分比 1=固定值',
  `num` int NOT NULL COMMENT '秒杀库存',
  `max_num` int DEFAULT NULL COMMENT '最大数量',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '活动名称',
  `status` int NOT NULL DEFAULT '1' COMMENT '活动状态 1 未开始 2 进行中 3结束  4预告  5已抢光',
  `type` tinyint(1) DEFAULT NULL COMMENT '活动类型',
  `starttime` timestamp NOT NULL COMMENT '活动开始时间',
  `endtime` timestamp NOT NULL COMMENT '活动结束时间',
  `isshow` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否显示 1 是 0 否',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 1 是 0 否',
  `create_date` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `update_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `isNotice` int NOT NULL DEFAULT '0' COMMENT '是否通知 0=未通知 1=已通知',
  `remind_json` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '是否推送过消息',
  `delete_method` int DEFAULT '0' COMMENT '删除方式 1手动删除 2定时任务删除 默认为0',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='秒杀活动';

-- ----------------------------
-- Records of lkt_seconds_activity
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_seconds_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_seconds_config`;
CREATE TABLE `lkt_seconds_config` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键自增',
  `store_id` int NOT NULL COMMENT '店铺id',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启 1 是 0 否',
  `buy_num` int NOT NULL COMMENT '秒杀商品默认限购数量',
  `imageurl` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '轮播图',
  `is_herald` int NOT NULL DEFAULT '0' COMMENT '是否开启预告',
  `heraldTime` int NOT NULL DEFAULT '0' COMMENT '预告时间 （单位:秒）',
  `remind` varchar(250) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `pcAdImg` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'PC端秒杀广告图设置',
  `rule` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则',
  `order_failure` int NOT NULL DEFAULT '0' COMMENT '订单失效 (单位 秒)',
  `order_after` int NOT NULL DEFAULT '604800' COMMENT '订单售后时间 (单位秒)',
  `auto_the_goods` int NOT NULL DEFAULT '7' COMMENT '自动收货时间',
  `deliver_remind` int DEFAULT NULL,
  `package_settings` tinyint NOT NULL DEFAULT '0' COMMENT '多件包邮设置 0.未开启 1.开启',
  `same_piece` int NOT NULL DEFAULT '0' COMMENT '同件',
  `same_order` int NOT NULL DEFAULT '0' COMMENT '同单',
  `auto_good_comment_day` int NOT NULL DEFAULT '0' COMMENT '自动评价设置几后自动好评',
  `mch_id` int NOT NULL COMMENT '店铺id',
  `auto_good_comment_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '自动评价内容',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='秒杀配置';

