  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `is_status` tinyint NOT NULL DEFAULT '0' COMMENT '签到插件是否启用 0：未启用 1：启用',
  `score_num` int NOT NULL DEFAULT '0' COMMENT '签到次数',
  `starttime` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '签到有效开始时间',
  `endtime` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '签到有效结束时间',
  `is_remind` tinyint NOT NULL DEFAULT '0' COMMENT '是否提醒 0：不提醒 1：提醒',
  `reset` int NOT NULL DEFAULT '0' COMMENT '间隔时间',
  `imgurl` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '图片',
  `score` int NOT NULL DEFAULT '0' COMMENT '领取积分',
  `continuity` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '连续设置',
  `detail` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '签到详情',
  `Instructions` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '积分使用说明',
  `modify_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `is_many_time` tinyint DEFAULT '0' COMMENT '是否允许多次 0:不允许  1:允许',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='签到配置表';

-- ----------------------------
-- Records of lkt_sign_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_sign_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_sign_record`;
CREATE TABLE `lkt_sign_record` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `sign_score` int NOT NULL DEFAULT '0' COMMENT '签到积分',
  `total_score` int NOT NULL DEFAULT '0' COMMENT '总积分',
  `record` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '事件',
  `score_invalid` timestamp NULL DEFAULT NULL COMMENT '积分过期时间  永不过期则为null',
  `sign_time` timestamp NULL DEFAULT NULL COMMENT '签到时间',
  `type` int NOT NULL DEFAULT '0' COMMENT '类型: 0:签到 1:消费 2:首次关注得积分 3:转积分给好友 4:好友转积分 5:系统扣除 6:系统充值 7:抽奖 8:会员购物积分 9:分销升级奖励积分 10:积分过期',
  `recovery` tinyint DEFAULT '0' COMMENT '是否删除 0.未删除 1.\r\n删除',
  `sNo` char(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单编号',
  `frozen_time` timestamp NULL DEFAULT NULL COMMENT '冻结结束时间',
  `notice` int NOT NULL DEFAULT '0' COMMENT '是否通知 0否1是',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_type` (`type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='签到记录（积分）';

-- ----------------------------
-- Records of lkt_sign_record
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_sku
-- ----------------------------
DROP TABLE IF EXISTS `lkt_sku`;
CREATE TABLE `lkt_sku` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `sid` int NOT NULL DEFAULT '0' COMMENT '上级ID',
  `code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '数据编码',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '数据名称',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '是否生效 0:不是 1:是',
  `type` tinyint NOT NULL DEFAULT '0' COMMENT '类型 1.属性名 2.属性值',
  `admin_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '管理员名称',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0:正常 1:回收',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `is_examine` int NOT NULL DEFAULT '0' COMMENT '审核状态 0.未审核  1.已审核',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `sid` (`sid`) USING BTREE,
  KEY `name` (`name`) USING BTREE,
  KEY `type` (`type`) USING BTREE,
  KEY `recycle` (`recycle`) USING BTREE,
  KEY `status` (`status`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='属性表';

-- ----------------------------
-- Records of lkt_sku
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_stock
-- ----------------------------
DROP TABLE IF EXISTS `lkt_stock`;
CREATE TABLE `lkt_stock` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `product_id` int NOT NULL DEFAULT '0' COMMENT '商品id',
  `attribute_id` int NOT NULL DEFAULT '0' COMMENT '属性id',
  `total_num` int NOT NULL COMMENT '总库存',
  `flowing_num` int NOT NULL DEFAULT '0' COMMENT '入库/出库',
  `type` tinyint NOT NULL DEFAULT '0' COMMENT '类型 0.入库 1.出库 2.预警',
  `user_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '购买方',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `content` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '内容',
  `mch_id` int DEFAULT NULL COMMENT '店铺id',
  `is_acceptance` int DEFAULT '0' COMMENT '是否受理 0.否 1.是',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `store_id` (`store_id`) USING BTREE,
  KEY `product_id` (`product_id`) USING BTREE,
  KEY `attribute_id` (`attribute_id`) USING BTREE,
  KEY `type` (`type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='库存记录表';

-- ----------------------------
-- Records of lkt_stock
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_subtraction
-- ----------------------------
DROP TABLE IF EXISTS `lkt_subtraction`;
CREATE TABLE `lkt_subtraction` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `mch_id` int NOT NULL DEFAULT '0' COMMENT '店主id',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动标题',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '活动名称',
  `subtraction_range` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '满减应用范围 ',
  `subtraction_parameter` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '满减范围参数',
  `subtraction_type` tinyint NOT NULL DEFAULT '0' COMMENT '满减类型 1.阶梯满减 2.循环满减 3.满赠 4.满件折扣',
  `subtraction` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '满减',
  `starttime` timestamp NULL DEFAULT NULL COMMENT '活动开始时间',
  `endtime` timestamp NULL DEFAULT NULL COMMENT '活动结束时间',
  `position_zfc` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '满减图片显示位置',
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '满减图片',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '活动状态 1.未开始 2.开启 3.关闭 4.已结束',
  `add_date` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='满减表';

-- ----------------------------
-- Records of lkt_subtraction
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_subtraction_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_subtraction_config`;
CREATE TABLE `lkt_subtraction_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `is_subtraction` tinyint NOT NULL DEFAULT '0' COMMENT '是否开启满减 0.否 1.是',
  `range_zfc` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '满减应用范围',
  `pro_id` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '满赠商品',
  `position_zfc` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '满减图片显示位置',
  `is_shipping` tinyint NOT NULL DEFAULT '0' COMMENT '满减包邮设置 0.否 1.是',
  `z_money` decimal(12,2) NOT NULL COMMENT '单笔满多少包邮',
  `address_id` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '不参与包邮地区',
  `add_date` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `mobile_terminal_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '移动端图片',
  `pc_side_picture` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'pc端图片',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='满减设置表';

-- ----------------------------
-- Records of lkt_subtraction_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_subtraction_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_subtraction_record`;
CREATE TABLE `lkt_subtraction_record` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `h_id` int NOT NULL DEFAULT '0' COMMENT '满减活动ID',
  `p_id` int NOT NULL DEFAULT '0' COMMENT '商品ID',
  `sNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户id',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '活动内容',
  `add_date` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='满减记录表';

