COMMIT;

-- ----------------------------
-- Table structure for lkt_supplier
-- ----------------------------
DROP TABLE IF EXISTS `lkt_supplier`;
CREATE TABLE `lkt_supplier` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL COMMENT '商城id',
  `account_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '账号',
  `password` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '密码',
  `logo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'LOGO',
  `supplier_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '供应商名称',
  `price` decimal(12,2) NOT NULL COMMENT '价格',
  `expire_date` timestamp NOT NULL COMMENT '到期时间',
  `dic_id` int NOT NULL COMMENT '供应商类型id',
  `business_scope` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '经营范围',
  `type` int NOT NULL DEFAULT '1' COMMENT '所属性质1.个人 2.企业',
  `business_license` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '营业执照',
  `contacts` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '联系人',
  `contact_phone` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '联系电话',
  `province` varchar(25) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '省级',
  `city` varchar(25) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '市级',
  `area` varchar(25) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '区级',
  `address` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '地址',
  `status` int NOT NULL DEFAULT '0' COMMENT '状态 0.正常 1.到期 2.锁定',
  `recovery` int NOT NULL DEFAULT '0' COMMENT '是否回收 0.否 1.是',
  `add_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `cumulative_balance` decimal(12,2) NOT NULL COMMENT '累计余额',
  `surplus_balance` decimal(12,2) NOT NULL COMMENT '剩余余额',
  `last_login_date` timestamp NULL DEFAULT NULL COMMENT '最后登录时间',
  `head_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '头像',
  `not_cashable_money` decimal(12,2) DEFAULT NULL,
  `source` int DEFAULT '0',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='供应商信息表';

-- ----------------------------
-- Records of lkt_supplier
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_supplier_account_log
-- ----------------------------
DROP TABLE IF EXISTS `lkt_supplier_account_log`;
CREATE TABLE `lkt_supplier_account_log` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `supplier_id` int NOT NULL COMMENT '供应商id',
  `amount` decimal(12,2) NOT NULL COMMENT '金额',
  `account_money` decimal(12,2) NOT NULL COMMENT '供应商余额',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：1.入账 2.出账',
  `type` tinyint NOT NULL DEFAULT '1' COMMENT '类型：1.订单 2.退款 3.提现',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '时间',
  `remake` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `source` int DEFAULT '0',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='供应商收支记录表';

-- ----------------------------
-- Records of lkt_supplier_account_log
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_supplier_bank_card
-- ----------------------------
DROP TABLE IF EXISTS `lkt_supplier_bank_card`;
CREATE TABLE `lkt_supplier_bank_card` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `store_id` int NOT NULL COMMENT '商城ID',
  `supplier_id` int NOT NULL COMMENT '供应商id',
  `Cardholder` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '开户人',
  `Bank_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '银行名称',
  `branch` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '支行名称',
  `Bank_card_number` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '银行卡号',
  `add_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '添加时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认 1默认',
  `recycle` tinyint(1) NOT NULL DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='供应商银行卡信息';

-- ----------------------------
-- Records of lkt_supplier_bank_card
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_supplier_brand
-- ----------------------------
DROP TABLE IF EXISTS `lkt_supplier_brand`;
CREATE TABLE `lkt_supplier_brand` (
  `brand_id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '品牌id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `brand_pic` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '品牌logo',
  `brand_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '广告图',
  `brand_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '品牌名称',
  `brand_y_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '英文名',
  `producer` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '产地',
  `remarks` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 0:启用 1:禁用',
  `brand_time` timestamp NULL DEFAULT NULL COMMENT '时间',
  `sort` int DEFAULT '100',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  `categories` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '所属分类',
  `supplier_id` int DEFAULT NULL COMMENT '供应商id',
  `examine` tinyint NOT NULL DEFAULT '0' COMMENT '审核状态 0.待审核 1.审核通过 2.不通过',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '审核备注',
  PRIMARY KEY (`brand_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商品品牌表';

-- ----------------------------
-- Records of lkt_supplier_brand
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_supplier_config
-- ----------------------------
DROP TABLE IF EXISTS `lkt_supplier_config`;
CREATE TABLE `lkt_supplier_config` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL COMMENT '商城id',
  `min_recharge` decimal(12,2) DEFAULT NULL COMMENT '最小充值金额',
  `min_withdrawal` decimal(12,2) DEFAULT NULL COMMENT '最小提现金额',
  `max_withdrawal` decimal(12,2) DEFAULT NULL COMMENT '最大提现金额',
  `commission` decimal(12,3) DEFAULT NULL COMMENT '手续费',
  `wallet_unit` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '钱包单位',
  `is_examine` int NOT NULL DEFAULT '1' COMMENT '供应商商品是否需要审核 0.否 1.是',
  `withdrawal_ins` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '提现说明',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='供应商配置表';

-- ----------------------------
-- Records of lkt_supplier_config
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_supplier_configure
-- ----------------------------
DROP TABLE IF EXISTS `lkt_supplier_configure`;
CREATE TABLE `lkt_supplier_configure` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '配置id',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '配置名称',
  `color` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '颜色',
  `size` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '尺码',
  `costprice` decimal(12,2) NOT NULL COMMENT '成本价',
  `price` decimal(12,2) NOT NULL COMMENT '出售价格',
  `yprice` decimal(12,2) NOT NULL COMMENT '供货价',
  `img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '图片',
  `pid` int NOT NULL COMMENT '商品id',
  `total_num` int NOT NULL DEFAULT '0' COMMENT '总库存',
  `num` int unsigned NOT NULL DEFAULT '0' COMMENT '剩余库存',
  `unit` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '单位',
  `bar_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '条形码',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 0:未开启砍价 1:开启砍价 2 上架 3 缺货 4下架',
  `attribute` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '属性',
  `recycle` tinyint NOT NULL DEFAULT '0' COMMENT '回收站 0.不回收 1.回收',
  `min_inventory` int NOT NULL DEFAULT '10' COMMENT '产品预警值',
  `ctime` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '修改时间',
  `attribute_str` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '属性ID字符串',
  `bargain_price` decimal(12,2) NOT NULL COMMENT '砍价价格',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `id` (`id`) USING BTREE,
  KEY `pid` (`pid`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='商品配置表';

-- ----------------------------
-- Records of lkt_supplier_configure
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_supplier_order_fright
-- ----------------------------
DROP TABLE IF EXISTS `lkt_supplier_order_fright`;
CREATE TABLE `lkt_supplier_order_fright` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL COMMENT '商城id',
  `sNo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单号',
  `total_fright` decimal(12,0) NOT NULL COMMENT '总运费',
  `supplier_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '供应商id',
  `is_settlement` int NOT NULL DEFAULT '0' COMMENT '是否结算 0.否 1.是',
