  `title` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '标题',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '内容',
  `time` timestamp NULL DEFAULT NULL COMMENT '时间',
  `type` int NOT NULL DEFAULT '1' COMMENT '1未读  2 已读',
