-- ----------------------------
-- Table structure for lkt_system_tell
-- ----------------------------
DROP TABLE IF EXISTS `lkt_system_tell`;
CREATE TABLE `lkt_system_tell` (
  `id` int NOT NULL AUTO_INCREMENT,
  `store_id` int DEFAULT '0' COMMENT '商城ID',
  `title` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '公告标题',
  `type` tinyint DEFAULT NULL COMMENT '公告类型: 1--系统维护  2--版本更新  3--普通公告',
  `startdate` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '开始时间',
  `enddate` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '结束时间',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '内容',
  `timetype` tinyint DEFAULT NULL COMMENT '时间类型: 1--区间时间  2--不限制',
  `add_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '添加时间',
  `is_read` int DEFAULT '0' COMMENT '是否已读取',
  `store_tell` int NOT NULL DEFAULT '1' COMMENT '管理后台公告  1未选择 2选择',
  `user_tell` int NOT NULL DEFAULT '1' COMMENT '用户公告  1未选择 2选择',
  `mch_tell` int NOT NULL DEFAULT '1' COMMENT '商户公告  1未选择 2选择',
  `supplier_tell` int NOT NULL DEFAULT '1' COMMENT '供应商公告  1未选择 2选择',
  `mch_son_tell` int NOT NULL DEFAULT '1' COMMENT '门店端公告  1未选择 2选择',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='系统公告表';

