  `store_id` int NOT NULL COMMENT '商城ID',
  `tell_id` int NOT NULL COMMENT '公告id',
  `read_id` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '标记以读用户id',
  `store_type` int NOT NULL COMMENT '标记以读用户所在端 1微信小程序 , 2 h5, 11 app, 7 pc店铺, 6 pc商城 8 管理后台 9 PC门店核销, 10H5门店核销',
