-- ----------------------------
-- Table structure for lkt_third
-- ----------------------------
DROP TABLE IF EXISTS `lkt_third`;
CREATE TABLE `lkt_third` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `ticket` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '获取token的凭证',
  `ticket_time` timestamp NULL DEFAULT NULL COMMENT '凭证更新时间',
  `token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '授权token',
  `token_expires` int DEFAULT NULL COMMENT 'token过期时间戳',
  `appid` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '第三方平台appid',
  `appsecret` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '第三方平台秘钥',
  `check_token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '消息检验Token，第三方平台设置',
  `encrypt_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '消息加减密key',
  `serve_domain` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '服务器域名',
  `work_domain` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '业务域名',
  `redirect_url` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '授权回调地址',
  `mini_url` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '小程序接口地址',
  `kefu_url` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '客服接口url',
  `qr_code` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '体验二维码url',
  `H5` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT 'H5页面地址',
  `endurl` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '根目录路径',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='第三方授权表';

