  `union_id` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '第三方用户主键id',
  `open_id` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci DEFAULT '0' COMMENT '第三方用户应用id',
  `user_id` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '系统用户id',
  `type` int DEFAULT '0' COMMENT '0=微信 1=支付宝',
  PRIMARY KEY (`id`) USING BTREE
