-- Table structure for lkt_third_template
-- ----------------------------
DROP TABLE IF EXISTS `lkt_third_template`;
CREATE TABLE `lkt_third_template` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `template_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '微信端模板id',
  `wx_desc` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'wx模板描述',
