  `wx_create_time` int DEFAULT NULL COMMENT '添加进开放平台模板库时间戳',
  `lk_version` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '后台定义的模板编号',
  `lk_desc` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '后台模板描述',
  `img_url` varchar(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '模板图片路劲',
  `store_id` int DEFAULT NULL COMMENT '商城id',
  `trade_data` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '数据字典-行业',
  `is_use` tinyint DEFAULT '1' COMMENT '是否应用 0：不应用 1：应用',
  `update_time` datetime DEFAULT NULL COMMENT '模板更新时间',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '模板名称',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='小程序模板表';

