-- ----------------------------
-- Table structure for lkt_user
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user`;
CREATE TABLE `lkt_user` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户id',
  `user_name` varchar(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户昵称',
  `cpc` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '86' COMMENT 'ITU电话区号',
  `country_num` int DEFAULT '156' COMMENT '国家代码',
  `access_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '授权id',
  `access_key` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '授权密钥',
  `wx_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '微信id',
  `wx_name` varbinary(150) DEFAULT NULL COMMENT '微信昵称',
  `gzh_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '公众号id',
  `zfb_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '支付宝id',
  `bd_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '百度id',
  `tt_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '头条id',
  `clientid` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '推送客户端ID',
  `sex` int NOT NULL DEFAULT '1' COMMENT '性别默认男 0:未知 1:男 2:女',
  `headimgurl` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '微信头像',
  `province` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '省',
  `city` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '市',
  `county` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '县',
  `detailed_address` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '详细地址',
  `money` decimal(12,2) DEFAULT '0.00' COMMENT '金额',
  `score` bigint unsigned DEFAULT '0' COMMENT '积分',
  `lock_score` int unsigned DEFAULT '0' COMMENT '冻结的积分',
  `password` char(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '支付密码',
  `Register_data` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '注册时间',
  `e_mail` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '邮箱',
  `real_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '真实姓名',
  `mobile` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '手机',
  `birthday` timestamp NULL DEFAULT NULL COMMENT '出生日期',
  `wechat_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '微信号',
  `address` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '地址',
  `Bank_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '银行名称',
  `Cardholder` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '持卡人',
  `Bank_card_number` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '银行卡号',
  `share_num` int DEFAULT '0' COMMENT '分享次数',
  `Referee` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '推荐人',
  `access_token` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '访问令牌',
  `consumer_money` decimal(12,2) DEFAULT NULL COMMENT '消费金',
  `img_token` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '分享图片id',
  `zhanghao` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `mima` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '密码',
  `source` tinyint NOT NULL DEFAULT '1' COMMENT '来源 1.小程序 2.app 3.支付宝小程序 4.头条小程序 5.百度小程序 6.pc端 7.H5',
  `login_num` int DEFAULT '0' COMMENT '登录次数',
  `verification_time` timestamp NULL DEFAULT NULL COMMENT '验证支付密码时间',
  `parameter` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '参数',
  `is_lock` tinyint DEFAULT '0' COMMENT '是否冻结 0-不冻结 1-冻结',
  `last_time` timestamp NULL DEFAULT NULL COMMENT '最后一次登录时间',
  `grade` int DEFAULT '0' COMMENT '会员级别 0--普通会员 ',
  `tui_id` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '会员推荐人id',
  `grade_add` timestamp NULL DEFAULT NULL COMMENT '充值会员等级时间',
  `grade_m` tinyint DEFAULT NULL COMMENT '开通方式 1-包月 2-包季 3-包年',
  `grade_end` timestamp NULL DEFAULT NULL COMMENT '会员等级到期时间',
  `is_out` tinyint DEFAULT '0' COMMENT '是否到期 0-未到期  1-已到期',
  `is_box` tinyint DEFAULT '1' COMMENT '是否同意续费弹框 0-不同意 1 同意',
  `mch_token` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '店铺token',
  `lang` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'zh-cn' COMMENT '语言',
  `user_from_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '兵器设备用户ID',
  `is_default_value` int DEFAULT '2' COMMENT '是否使用的默认用户配置   1是 2否  默认否',
  `is_default_birthday` int DEFAULT '2' COMMENT '是否使用的默认日期配置   1是 2否  默认否',
  `token_living_pc` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '主播pc的token',
  `fans_num` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `index_user_id` (`user_id`) USING BTREE,
  KEY `index_store_id` (`store_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='会员列表';

-- ----------------------------
-- Records of lkt_user
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_user_address
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user_address`;
CREATE TABLE `lkt_user_address` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT '地址id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `name` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '收货人',
  `tel` char(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '联系方式',
  `sheng` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '省id',
  `city` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '市id',
  `quyu` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '区域id',
  `address` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '收货地址（不加省市区）',
  `address_xq` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '省市区+详细地址',
  `code` int NOT NULL DEFAULT '0' COMMENT '邮政编号',
  `uid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '用户ID',
  `is_default` tinyint NOT NULL DEFAULT '0' COMMENT '是否默认地址 1默认',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='用户收货地址表';

