-- ----------------------------
-- Table structure for lkt_user_collection
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user_collection`;
CREATE TABLE `lkt_user_collection` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '用户ID',
  `p_id` int DEFAULT NULL COMMENT '产品id',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `mch_id` int DEFAULT '0' COMMENT '店铺ID',
  `type` int DEFAULT '1' COMMENT '收藏类型 1.普通收藏 2.积分商城收藏',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='收藏表';

