-- ----------------------------
-- Table structure for lkt_user_distribution
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user_distribution`;
CREATE TABLE `lkt_user_distribution` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `pid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '上级id',
  `level` int NOT NULL COMMENT '等级',
  `lt` int NOT NULL COMMENT 'lt',
  `rt` int NOT NULL COMMENT 'rt',
  `uplevel` int NOT NULL COMMENT '第几代',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  `usets` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `commission` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '个人佣金',
  `onlyamount` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT '累计消费',
  `allamount` decimal(15,2) NOT NULL DEFAULT '0.00' COMMENT '销售业绩',
  `one_put` decimal(11,2) unsigned NOT NULL DEFAULT '0.00' COMMENT '个人进货奖励已经发放最大条件',
  `team_put` decimal(11,2) NOT NULL DEFAULT '0.00' COMMENT '团队业绩奖励已经发放最大',
  `accumulative` decimal(12,2) DEFAULT NULL COMMENT '累计佣金',
  `tx_commission` decimal(12,2) DEFAULT NULL COMMENT '可提现佣金',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='分销关联表';

-- ----------------------------
-- Records of lkt_user_distribution
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_user_first
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user_first`;
CREATE TABLE `lkt_user_first` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `user_id` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户id',
  `grade_id` int DEFAULT NULL COMMENT '会员等级id',
  `level` int DEFAULT NULL COMMENT '首次开通会员级别',
  `store_id` int DEFAULT NULL COMMENT '商城id',
  `is_use` tinyint DEFAULT '0' COMMENT '是否使用了首次开通赠送商品券 0-未使用 1-已使用',
  `sNo` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '订单编号',
  `end_time` datetime DEFAULT NULL COMMENT '兑换券失效时间',
  `attr_id` int DEFAULT NULL COMMENT '兑换商品的规格id',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='等级会员首次开通表';

-- ----------------------------
-- Records of lkt_user_first
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_user_footprint
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user_footprint`;
CREATE TABLE `lkt_user_footprint` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `p_id` int DEFAULT NULL COMMENT '产品id',
  `app_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'mini_program' COMMENT '平台类型',
  `add_time` timestamp NULL DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='足迹表';

-- ----------------------------
-- Records of lkt_user_footprint
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_user_grade
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user_grade`;
CREATE TABLE `lkt_user_grade` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `name` char(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '等级名称',
  `rate` decimal(12,2) DEFAULT NULL COMMENT '打折率',
  `money` decimal(12,2) DEFAULT NULL COMMENT '包月金额',
  `store_id` int unsigned DEFAULT NULL COMMENT '商城id',
  `money_j` decimal(12,2) DEFAULT NULL COMMENT '包季金额',
  `money_n` decimal(12,2) DEFAULT NULL COMMENT '包年金额',
  `remark` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '备注',
  `imgurl` char(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '会员充值背景图',
  `imgurl_my` char(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '我的会员背景展示图',
  `imgurl_s` char(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '等级中心背景图',
  `level` int DEFAULT NULL COMMENT '会员级别 普通-0   白银-1  黄金-2  黑金-3',
  `pro_id` int DEFAULT NULL COMMENT '赠送商品id',
  `font_color` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '会员昵称字体颜色',
  `date_color` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '标识文字颜色',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='会员等级表';

-- ----------------------------
-- Records of lkt_user_grade
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_user_role
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user_role`;
CREATE TABLE `lkt_user_role` (
  `id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'id',
  `main_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '归类主键id(例如 门店id/店铺id/商城id)',
  `type` int NOT NULL COMMENT '1=门店id 2=店铺id 3=商城id',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '角色名称',
  `text` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '角色说明',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `update_date` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='通用菜单角色表';

-- ----------------------------
-- Records of lkt_user_role
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_user_rule
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user_rule`;
CREATE TABLE `lkt_user_rule` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `rate_now` decimal(12,2) DEFAULT NULL COMMENT '默认折率',
  `active` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '1' COMMENT '支持的插件使用折率：1--正价商品 2--支持拼团 3--支持砍价 4--支持竞拍  5--分销  6--秒杀',
  `rule` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '会员等级规则详情',
  `wait` int DEFAULT NULL COMMENT '有效期',
  `store_id` int unsigned DEFAULT NULL COMMENT '商城id',
  `is_auto` tinyint DEFAULT '1' COMMENT '是否开启自动续费 0-不开启 1-开启',
  `auto_time` int unsigned DEFAULT NULL COMMENT '自动续费提前提醒时间（天）',
  `method` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '开通方式 1-包月 2-包季 3-包年',
  `is_wallet` tinyint DEFAULT '1' COMMENT '是否开启余额支付 0-不开启 1-开启',
  `upgrade` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '1' COMMENT '升级方式 1-购买会员服务 2-补差额',
  `is_birthday` tinyint DEFAULT '0' COMMENT '是否开启生日特权 0-不开启 1-开启',
  `bir_multiple` int DEFAULT '1' COMMENT '生日特权积分倍数',
  `is_product` tinyint DEFAULT '0' COMMENT '是否开启会员赠送商品 0-不开启 1-开启',
  `bond` decimal(12,2) NOT NULL COMMENT '提现保证金',
  `is_jifen` tinyint DEFAULT '0' COMMENT '会员等比例积分 0-不开启 1-开启',
  `jifen_m` tinyint DEFAULT '1' COMMENT '积分发送规则 0-付款后 1-收货后',
  `back` tinyint DEFAULT NULL COMMENT '是否开启返现 0-不开启 1-开启',
  `back_scale` decimal(12,2) DEFAULT NULL COMMENT '返现比例',
  `poster` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '会员分享海报',
  `is_limit` tinyint DEFAULT '0' COMMENT '是否开启推荐限制 0-不限制  1-限制',
  `level` int DEFAULT NULL COMMENT '可以推荐的会员级别',
  `distribute_l` int DEFAULT '0' COMMENT '可以参与分销的会员级别id',
  `valid` int DEFAULT '7' COMMENT '增送商品的有效天数',
  `score` int DEFAULT '0' COMMENT '积分过期设置',
  `bonus_points_shopping` tinyint DEFAULT '0' COMMENT '购物赠送积分 0.未开启 \r\n\r\n1.开启',
  `proportion_of_gifts` int DEFAULT '0' COMMENT '赠送比例',
  `release_time` tinyint DEFAULT '1' COMMENT '发放时间 1.收货后  2.付款后',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='会员规则表';

-- ----------------------------
-- Records of lkt_user_rule
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_user_search
-- ----------------------------
DROP TABLE IF EXISTS `lkt_user_search`;
CREATE TABLE `lkt_user_search` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'token',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户ID',
  `keyword` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '搜索词',
  `add_date` datetime DEFAULT NULL COMMENT '添加时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='用户搜索表';

-- ----------------------------
-- Records of lkt_user_search
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_withdraw
-- ----------------------------
DROP TABLE IF EXISTS `lkt_withdraw`;
CREATE TABLE `lkt_withdraw` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_id` int NOT NULL DEFAULT '0' COMMENT '商城id',
  `user_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户id',
  `name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '名称',
  `wx_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '微信id',
  `mobile` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '手机',
  `Bank_id` int DEFAULT NULL COMMENT '银行卡id',
  `money` decimal(12,2) NOT NULL COMMENT '提现金额',
  `z_money` decimal(12,2) NOT NULL COMMENT '剩余金额',
  `s_charge` decimal(12,2) NOT NULL COMMENT '手续费',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态 0：审核中 1：审核通过 2：拒绝',
  `add_date` timestamp NULL DEFAULT NULL COMMENT '申请时间',
  `refuse` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '拒绝原因',
  `is_mch` int DEFAULT '0' COMMENT '是否是店铺提现',
  `txsno` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '提现订单号',
  `examine_date` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '提现审核时间',
  `withdraw_status` int NOT NULL DEFAULT '1' COMMENT '提现类型 1银行卡  2微信余额  3贝宝余额',
  `wx_status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '提现到微信余额提现状态：1进行中 2已完成 3提现失败',
  `recovery` tinyint DEFAULT '0' COMMENT '是否回收 0.未回收 1.回收',
  `wx_open_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户openid',
  `wx_son` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '微信提现到零钱订单号',
  `wx_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户微信名称',
  `realname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '用户微信余额提现真实姓名',
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '贝宝提现邮箱',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='提现列表';

-- ----------------------------
-- Records of lkt_withdraw
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for lkt_write_record
-- ----------------------------
DROP TABLE IF EXISTS `lkt_write_record`;
CREATE TABLE `lkt_write_record` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id',
  `write_store_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '核销门店id',
  `write_time` timestamp NULL DEFAULT NULL COMMENT '核销时间',
  `write_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '核销码',
  `s_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin DEFAULT NULL COMMENT '订单号',
  `p_id` int DEFAULT NULL COMMENT '订单详情id',
  `status` int DEFAULT NULL COMMENT '核销状态，1为已核销完，2为退款状态中，3为还有核销次数 , 4为退款成功',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='核销记录表';

-- ----------------------------
-- Records of lkt_write_record
-- ----------------------------
BEGIN;
COMMIT;

